"use client";

import Link from "next/link";
import { useQuery } from "@tanstack/react-query";
import { motion } from "framer-motion";
import { format } from "date-fns";
import { pt } from "date-fns/locale";
import { getToken } from "@/app/lib/auth";
import { fetchAdminStats, fetchAdminLogs, type AdminStats } from "@/app/lib/admin";
import {
  AdminPageHeader,
  AdminCard,
  AdminSection,
  buildBreadcrumbs,
} from "@/app/admin/_components";
import { fadeInUp, transitionSmooth, staggerContainer, staggerItem } from "@/app/lib/animations";

type StatItem = { key: keyof AdminStats; label: string; href: string; group: string };

const STATS: StatItem[] = [
  { key: "totalUtilizadores", label: "Utilizadores", href: "/admin/utilizadores", group: "Contas" },
  { key: "totalEncomendas", label: "Encomendas", href: "/encomendas", group: "Encomendas" },
  { key: "encomendasEsteMes", label: "Este m├¬s", href: "/encomendas", group: "Encomendas" },
  { key: "totalServicos", label: "Servi├ºos", href: "/servicos", group: "Servi├ºos" },
  { key: "servicosEsteMes", label: "Este m├¬s", href: "/servicos", group: "Servi├ºos" },
  { key: "totalClientes", label: "Clientes", href: "/clientes", group: "Entidades" },
  { key: "totalFuncionarios", label: "Funcion├írios", href: "/funcionarios", group: "Entidades" },
  { key: "totalProdutos", label: "Produtos", href: "/produtos", group: "Armaz├®m" },
  { key: "totalPaiois", label: "Pai├│is", href: "/armazem/gestao", group: "Armaz├®m" },
  { key: "totalLogs", label: "Logs", href: "/admin/logs", group: "Sistema" },
];

const GROUPS_ORDER = ["Contas", "Encomendas", "Servi├ºos", "Entidades", "Armaz├®m", "Sistema"];

function groupStats(stats: StatItem[]) {
  const map = new Map<string, StatItem[]>();
  for (const s of stats) {
    const list = map.get(s.group) ?? [];
    list.push(s);
    map.set(s.group, list);
  }
  return GROUPS_ORDER.filter((g) => map.has(g)).map((g) => ({ group: g, items: map.get(g)! }));
}

export default function AdminDashboardPage() {
  const token = getToken();
  const { data: stats, isLoading: loadingStats } = useQuery({
    queryKey: ["admin", "stats"],
    queryFn: () => fetchAdminStats(token!),
    enabled: !!token,
    staleTime: 60 * 1000,
  });
  const { data: logsData, isLoading: loadingLogs } = useQuery({
    queryKey: ["admin", "logs", 1],
    queryFn: () => fetchAdminLogs(token!, { pagina: 1, itensPorPagina: 10 }),
    enabled: !!token,
    staleTime: 30 * 1000,
  });
  const ultimosLogs = logsData?.items ?? [];
  const grouped = groupStats(STATS);

  return (
    <motion.div
      initial="initial"
      animate="animate"
      variants={staggerContainer}
      className="space-y-10"
    >
      <AdminPageHeader
        title="Dashboard"
        description="Vis├úo geral do sistema e atividade recente."
        breadcrumb={buildBreadcrumbs("/admin")}
      />

      {grouped.map(({ group, items }) => (
        <AdminSection
          key={group}
          title={group}
          description={`M├®tricas de ${group.toLowerCase()}.`}
        >
          <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5">
            {loadingStats
              ? items.map((_, i) => (
                  <div key={i} className="rounded-2xl border border-[#e7e5e4] bg-white p-4 dark:border-[#222] dark:bg-[#111]">
                    <div className="h-7 w-14 animate-pulse rounded bg-[#e7e5e4] dark:bg-[#333]" />
                    <div className="mt-2 h-4 w-20 animate-pulse rounded bg-[#e7e5e4] dark:bg-[#333]" />
                  </div>
                ))
              : items.map((item, i) => (
                  <motion.div
                    key={item.key}
                    variants={staggerItem}
                    transition={{ ...transitionSmooth, delay: i * 0.02 }}
                  >
                    <Link href={item.href} className="block">
                      <AdminCard>
                        <p className="text-2xl font-bold tabular-nums text-[#1c1917] dark:text-white">
                          {stats ? String(stats[item.key] ?? "ÔÇö") : "ÔÇö"}
                        </p>
                        <p className="mt-1 text-sm text-[#57534e] dark:text-[#888]">
                          {item.label}
                        </p>
                      </AdminCard>
                    </Link>
                  </motion.div>
                ))}
          </div>
        </AdminSection>
      ))}

      <AdminSection
        title="Atividade recente"
        description="├Ültimas a├º├Áes registadas no sistema."
        action={
          <Link
            href="/admin/logs"
            className="text-sm font-medium text-[#ea580c] hover:underline dark:text-[#f97316]"
          >
            Ver todos os logs ÔåÆ
          </Link>
        }
      >
        <AdminCard padding={false} className="overflow-hidden">
          {loadingLogs ? (
            <ul className="divide-y divide-[#e7e5e4] dark:divide-[#222]">
              {[1, 2, 3, 4, 5].map((i) => (
                <li key={i} className="flex items-center gap-4 px-5 py-4">
                  <span className="h-4 w-24 animate-pulse rounded bg-[#e7e5e4] dark:bg-[#333]" />
                  <span className="h-4 flex-1 animate-pulse rounded bg-[#e7e5e4] dark:bg-[#333]" />
                </li>
              ))}
            </ul>
          ) : ultimosLogs.length === 0 ? (
            <p className="py-10 text-center text-sm text-[#78716c] dark:text-[#888]">
              Nenhum registo de atividade.
            </p>
          ) : (
            <ul className="divide-y divide-[#e7e5e4] dark:divide-[#222]">
              {ultimosLogs.map((log) => (
                <li
                  key={log.id}
                  className="flex flex-wrap items-center gap-x-4 gap-y-1 px-5 py-3 text-sm"
                >
                  <span className="tabular-nums text-[#78716c] dark:text-[#666]">
                    {log.timestamp
                      ? format(new Date(log.timestamp), "dd/MM/yyyy HH:mm", { locale: pt })
                      : "ÔÇö"}
                  </span>
                  <span className="rounded bg-[#f1f5f9] px-2 py-0.5 font-medium text-[#475569] dark:bg-[#222] dark:text-[#94a3b8]">
                    {log.acao}
                  </span>
                  {log.userName && (
                    <span className="text-[#57534e] dark:text-[#a3a3a3]">{log.userName}</span>
                  )}
                  {log.jsonDados && (
                    <span
                      className="max-w-xs truncate text-xs text-[#a8a29e] dark:text-[#555]"
                      title={log.jsonDados}
                    >
                      {log.jsonDados}
                    </span>
                  )}
                </li>
              ))}
            </ul>
          )}
        </AdminCard>
      </AdminSection>

      <AdminSection
        title="A├º├Áes r├ípidas"
        description="Acesso direto ├ás ├íreas do sistema."
      >
        <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-3">
          {[
            { label: "Utilizadores", href: "/admin/utilizadores" },
            { label: "Clientes", href: "/clientes" },
            { label: "Funcion├írios", href: "/funcionarios" },
            { label: "Encomendas", href: "/encomendas" },
            { label: "Servi├ºos", href: "/servicos" },
            { label: "Armaz├®m", href: "/armazem" },
            { label: "Produtos", href: "/produtos" },
            { label: "Logs do sistema", href: "/admin/logs" },
            { label: "Defini├º├Áes", href: "/admin/definicoes" },
          ].map((item) => (
            <Link key={item.href} href={item.href}>
              <AdminCard className="flex flex-row items-center justify-between">
                <span className="font-medium text-[#1c1917] dark:text-white">{item.label}</span>
                <span className="text-[#a8a29e] dark:text-[#555]">ÔåÆ</span>
              </AdminCard>
            </Link>
          ))}
        </div>
      </AdminSection>
    </motion.div>
  );
}

"use client";

import { useState, useEffect, useRef } from "react";
import Link from "next/link";
import { useParams, usePathname, useRouter } from "next/navigation";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { motion } from "framer-motion";
import { fetchUtilizadorParaEditar, updateUtilizador, type EditarUtilizadorModel } from "@/app/lib/admin";
import { getToken } from "@/app/lib/auth";
import { AdminPageHeader, AdminCard, buildBreadcrumbs } from "@/app/admin/_components";
import { fadeInUp, transitionSmooth } from "@/app/lib/animations";

const cardClass =
  "rounded-2xl border border-[#e7e5e4] bg-white p-6 shadow-[0_1px_3px_rgba(0,0,0,0.06)] dark:border-[#222] dark:bg-[#111] sm:p-8";

const labelClass = "block text-sm font-medium text-gray-700 dark:text-gray-300";

const inputClass =
  "mt-2 w-full rounded-xl border border-gray-300 bg-white px-4 py-3 text-gray-900 focus:border-[#f97316] focus:outline-none focus:ring-2 focus:ring-[#f97316]/20 dark:border-[#333] dark:bg-[#1a1a1a] dark:text-white";

const btnPrimary =
  "data-button rounded-xl bg-[#f97316] px-5 py-2.5 text-sm font-semibold text-black transition-[opacity,background-color] duration-200 hover:opacity-90 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[#f97316]";

const btnSecondary =
  "data-button rounded-xl border border-gray-300 px-5 py-2.5 text-sm font-medium text-gray-700 transition-[border-color,background-color,color] duration-200 hover:bg-gray-50 dark:border-[#333] dark:text-gray-300 dark:hover:bg-[#1a1a1a]";

export default function EditarUtilizadorPage() {
  const params = useParams();
  const pathname = usePathname();
  const router = useRouter();
  const queryClient = useQueryClient();
  const id = params.id as string;
  const [mounted, setMounted] = useState(false);
  const [model, setModel] = useState<EditarUtilizadorModel | null>(null);
  const [funcionariosDisponiveis, setFuncionariosDisponiveis] = useState<{ id: number; nomeCompleto: string }[]>([]);
  const submittingRef = useRef(false);
  const [message, setMessage] = useState<{ type: "error"; text: string } | null>(null);

  useEffect(() => {
    setMounted(true);
  }, []);

  const { data: editData, isLoading: loading } = useQuery({
    queryKey: ["admin", "utilizador", id],
    queryFn: async () => {
      const token = getToken();
      if (!token) {
        router.replace("/login");
        throw new Error("no-token");
      }
      return fetchUtilizadorParaEditar(token, id);
    },
    enabled: mounted && !!id,
    retry: 1,
  });

  useEffect(() => {
    if (loading) return;
    if (editData) {
      setModel(editData.model);
      setFuncionariosDisponiveis(editData.funcionariosDisponiveis);
    } else {
      setModel(null);
      setFuncionariosDisponiveis([]);
    }
  }, [editData, loading]);

  const saveMutation = useMutation({
    mutationFn: async (m: EditarUtilizadorModel) => {
      const token = getToken();
      if (!token) {
        router.replace("/login");
        throw new Error("Sess├úo expirada.");
      }
      await updateUtilizador(token, id, m);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["admin", "utilizadores"] });
      router.push("/admin/utilizadores");
    },
    onError: (e: Error) => {
      setMessage({ type: "error", text: e.message || "Erro ao guardar." });
    },
  });

  const toggleRole = (nome: string) => {
    if (!model) return;
    setModel({
      ...model,
      roles: model.roles.map((r) =>
        r.nome === nome ? { ...r, atribuido: !r.atribuido } : r
      ),
    });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (submittingRef.current || saveMutation.isPending) return;
    if (!model) return;
    setMessage(null);
    submittingRef.current = true;
    try {
      await saveMutation.mutateAsync(model);
    } finally {
      submittingRef.current = false;
    }
  };

  const submitting = saveMutation.isPending;

  if (!mounted || loading) {
    return (
      <div className="flex min-h-[200px] items-center justify-center">
        <div className="h-8 w-8 animate-spin rounded-full border-2 border-[#f97316] border-t-transparent" />
      </div>
    );
  }

  if (!model) {
    return (
      <div className="space-y-6">
        <AdminPageHeader
          title="Utilizador n├úo encontrado"
          breadcrumb={buildBreadcrumbs("/admin/utilizadores")}
        />
        <p className="text-[#57534e] dark:text-[#888]">O utilizador solicitado n├úo existe ou foi removido.</p>
        <Link href="/admin/utilizadores" className="inline-block text-[#f97316] hover:underline">
          ÔåÉ Voltar a Utilizadores
        </Link>
      </div>
    );
  }

  return (
    <div className="space-y-8">
      <AdminPageHeader
        title="Editar utilizador"
        description={`${model.userName} ┬À ${model.email}`}
        breadcrumb={pathname ? buildBreadcrumbs(pathname) : buildBreadcrumbs("/admin/utilizadores/editar")}
      />
      <div className="mx-auto max-w-2xl">

      <form onSubmit={handleSubmit} className="space-y-6">
            <motion.section
              initial={fadeInUp.initial}
              animate={fadeInUp.animate}
              transition={{ ...transitionSmooth, delay: 0.05 }}
              className={cardClass}
            >
              <h2 className="text-lg font-semibold text-[#1c1917] dark:text-white">Roles (cargos)</h2>
              <p className="mt-1 text-sm text-gray-600 dark:text-gray-400">
                Marque os cargos a atribuir a este utilizador.
              </p>
              <div className="mt-4 flex flex-wrap gap-4">
                {model.roles.map((r) => (
                  <label key={r.nome} className="flex items-center gap-2">
                    <input
                      type="checkbox"
                      checked={r.atribuido}
                      onChange={() => toggleRole(r.nome)}
                      className="rounded border-gray-300 text-[#f97316] focus:ring-[#f97316]"
                    />
                    <span className="text-sm font-medium text-gray-700 dark:text-gray-300">{r.nome}</span>
                  </label>
                ))}
              </div>
            </motion.section>

            <motion.section
              initial={fadeInUp.initial}
              animate={fadeInUp.animate}
              transition={{ ...transitionSmooth, delay: 0.1 }}
              className={`mt-6 ${cardClass}`}
            >
              <h2 className="text-lg font-semibold text-[#1c1917] dark:text-white">Funcion├írio associado</h2>
              <p className="mt-1 text-sm text-[#57534e] dark:text-[#888]">
                Opcional. Se escolher um funcion├írio, esta conta fica ligada ├á ficha do funcion├írio.
              </p>
              <div className="mt-4">
                <label htmlFor="funcionarioId" className={labelClass}>Funcion├írio</label>
                <select
                  id="funcionarioId"
                  value={model.funcionarioId ?? ""}
                  onChange={(e) =>
                    setModel({
                      ...model,
                      funcionarioId: e.target.value === "" ? null : Number(e.target.value),
                    })
                  }
                  className={inputClass}
                >
                  <option value="">ÔÇö Nenhum ÔÇö</option>
                  {funcionariosDisponiveis.map((f) => (
                    <option key={f.id} value={f.id}>
                      {f.nomeCompleto}
                    </option>
                  ))}
                </select>
              </div>
            </motion.section>

            {message && (
              <p className="mt-4 text-sm text-red-600 dark:text-red-400">{message.text}</p>
            )}

            <div className="mt-8 flex gap-3">
              <button type="submit" disabled={submitting} className={btnPrimary}>
                {submitting ? "A guardarÔÇª" : "Guardar"}
              </button>
              <Link href="/admin/utilizadores" className={btnSecondary}>
                Cancelar
              </Link>
            </div>
      </form>
      </div>
    </div>
  );
}

