"use client";

import { useState, useEffect, Suspense } from "react";
import Link from "next/link";
import { useSearchParams, useRouter } from "next/navigation";
import { useQuery } from "@tanstack/react-query";
import { motion } from "framer-motion";
import Navbar, { CONTENT_OFFSET_TOP } from "@/app/components/Navbar";
import { getToken } from "@/app/lib/auth";
import { useUser } from "@/app/context/UserContext";
import { labelPerfilRisco } from "@/app/lib/armazem";
import { fetchGestao } from "@/app/lib/paiolApi";
import { fadeInUp, transitionSmooth } from "@/app/lib/animations";

import { apiPath } from "@/app/lib/apiConfig";

const btnPrimary =
  "data-button rounded-xl bg-[#f97316] px-4 py-2 text-sm font-semibold text-black transition-[opacity,background-color] duration-200 hover:opacity-90 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[#f97316]";

const btnSecondary =
  "data-button rounded-xl border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 transition-[border-color,background-color,color] duration-200 hover:bg-gray-50 dark:border-[#333] dark:text-gray-300 dark:hover:bg-[#1a1a1a]";

type PaiolLinha = {
  id: string;
  nome: string;
  localizacao?: string;
  limiteMLE: number;
  perfilRisco: string;
  estado: string;
  mleAtual: number;
  percentagemOcupacao: number;
};

function mapGestaoToPaiois(data: unknown): PaiolLinha[] {
  const list = Array.isArray(data) ? data : [];
  return list.map((item: Record<string, unknown>) => {
    const p = (item.Paiol ?? item.paiol ?? {}) as Record<string, unknown>;
    const mle = Number(item.MleAtual ?? item.mleAtual ?? 0);
    const pct = Number(item.PercentagemOcupacao ?? item.percentagemOcupacao ?? 0);
    const limite = Number(p.LimiteMLE ?? p.limiteMLE ?? 0);
    return {
      id: String(p.Id ?? p.id ?? ""),
      nome: String(p.Nome ?? p.nome ?? "").trim() || "ÔÇö",
      localizacao: (p.Localizacao ?? p.localizacao) as string | undefined,
      limiteMLE: Number.isFinite(limite) ? limite : 0,
      perfilRisco: String(p.PerfilRisco ?? p.perfilRisco ?? ""),
      estado: String(p.Estado ?? p.estado ?? ""),
      mleAtual: Number.isFinite(mle) ? mle : 0,
      percentagemOcupacao: Number.isFinite(pct) ? pct : 0,
    };
  });
}

function GestaoContent() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const { user } = useUser();
  const canGerirArmazem = (user?.permissions ?? []).includes("armazem.gerir");
  const [mounted, setMounted] = useState(false);
  const token = getToken();

  const {
    data: paiois = [],
    isLoading: loading,
    error: queryError,
  } = useQuery({
    queryKey: ["armazem", "gestao", canGerirArmazem],
    queryFn: async (): Promise<PaiolLinha[]> => {
      if (!token) {
        router.replace("/login");
        throw new Error("Sess├úo expirada.");
      }
      const data = canGerirArmazem
        ? await fetchGestao(token)
        : await fetch(apiPath("api/paiol"), { headers: { Authorization: `Bearer ${token}` } }).then(async (res) => {
            if (res.status === 401) {
              router.replace("/login");
              throw new Error("N├úo autenticado");
            }
            if (!res.ok) throw new Error("Erro ao carregar pai├│is");
            return res.json();
          });
      return mapGestaoToPaiois(data);
    },
    staleTime: 30 * 1000,
    retry: 2,
    enabled: mounted && !!token,
  });

  const criado = searchParams.get("criado") === "1";
  const editado = searchParams.get("editado") === "1";
  const eliminado = searchParams.get("eliminado") === "1";

  useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-[#fafafa] dark:bg-[#0a0a0a]">
        <div className="h-8 w-8 animate-spin rounded-full border-2 border-[#f97316] border-t-transparent" />
      </div>
    );
  }

  const mostrarLista = !loading && !queryError && paiois.length > 0;
  const mostrarVazio = !loading && !queryError && paiois.length === 0;
  const mostrarErro = !loading && !!queryError;

  const alerta =
    criado ? "Paiol criado com sucesso."
    : editado ? "Altera├º├Áes guardadas."
    : eliminado ? "Paiol eliminado com sucesso."
    : null;

  return (
    <div className="min-h-screen bg-[#f8f7f5] text-[#1c1917] dark:bg-[#0a0a0a] dark:text-white">
      <Navbar />

      <main
        className="relative px-6 pt-14 pb-10 sm:px-8"
        style={{ paddingTop: CONTENT_OFFSET_TOP }}
      >
        <div className="mx-auto max-w-6xl">
          <motion.div
            initial={fadeInUp.initial}
            animate={fadeInUp.animate}
            transition={transitionSmooth}
            className="flex flex-col gap-5 sm:flex-row sm:flex-wrap sm:items-center sm:justify-between"
          >
            <div>
              <h1 className="font-heading text-2xl tracking-tight text-[#1c1917] dark:text-white sm:text-3xl">
                Gest├úo de Pai├│is
              </h1>
              <p className="mt-1 text-[#57534e] dark:text-gray-400">
                Criar, editar e eliminar pai├│is. Admin e Gestor.
              </p>
            </div>
            <div className="flex flex-wrap gap-2">
              <Link href="/armazem/entradas/registar" className={btnSecondary}>
                Registar entrada
              </Link>
              <Link href="/armazem/movimentos" className={btnSecondary}>
                Movimentos
              </Link>
              <Link href="/armazem" className={btnSecondary}>
                Voltar ao Armaz├®m
              </Link>
              <Link href="/armazem/novo" className={btnPrimary}>
                Criar novo paiol
              </Link>
            </div>
          </motion.div>

          {alerta && (
            <motion.p
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={transitionSmooth}
              className="mt-5 rounded-xl bg-green-100 px-4 py-3 text-sm text-green-800 dark:bg-green-900/30 dark:text-green-400"
            >
              {alerta}
            </motion.p>
          )}

          <motion.div
            initial={fadeInUp.initial}
            animate={fadeInUp.animate}
            transition={{ ...transitionSmooth, delay: 0.05 }}
            className="card-hover mt-10 rounded-2xl border border-[#e7e5e4] bg-white p-5 shadow-[0_1px_3px_rgba(0,0,0,0.06)] dark:border-[#1f1f1f] dark:bg-[#111] dark:shadow-none sm:p-6"
          >
            {loading ? (
              <div className="flex justify-center py-12">
                <div className="h-8 w-8 animate-spin rounded-full border-2 border-[#f97316] border-t-transparent" />
              </div>
            ) : mostrarErro ? (
              <p className="rounded-xl bg-red-100 px-4 py-3 text-sm text-red-800 dark:bg-red-900/30 dark:text-red-400">
                {queryError instanceof Error ? queryError.message : "Erro ao carregar dados."}
              </p>
            ) : mostrarVazio ? (
              <div className="rounded-xl border border-dashed border-[#e7e5e4] bg-[#fafaf9] py-12 text-center dark:border-[#333] dark:bg-[#0a0a0a]">
                <p className="text-[#57534e] dark:text-gray-400">
                  Ainda n├úo h├í pai├│is com acesso. Crie o primeiro (em Criar novo paiol marque pelo menos um cargo com acesso, ex. Admin).
                </p>
                <Link href="/armazem/novo" className={btnPrimary + " mt-4 inline-block"}>
                  Criar novo paiol
                </Link>
              </div>
            ) : mostrarLista ? (
              <>
                <p className="mb-4 text-sm text-[#57534e] dark:text-gray-400">
                  {paiois.length} paiol/pai├│is
                </p>
                <div className="overflow-x-auto">
                  <table className="w-full min-w-[720px] text-left text-sm">
                    <thead>
                      <tr className="border-b border-[#e7e5e4] dark:border-[#222]">
                        <th className="pb-3 font-semibold text-[#444] dark:text-gray-300">Nome</th>
                        <th className="pb-3 font-semibold text-[#444] dark:text-gray-300">Localiza├º├úo</th>
                        <th className="pb-3 font-semibold text-[#444] dark:text-gray-300">Limite MLE (kg)</th>
                        <th className="pb-3 font-semibold text-[#444] dark:text-gray-300">Perfil de risco</th>
                        <th className="pb-3 font-semibold text-[#444] dark:text-gray-300">Ocupa├º├úo</th>
                        <th className="pb-3 font-semibold text-[#444] dark:text-gray-300">Estado</th>
                        <th className="pb-3 font-semibold text-[#444] dark:text-gray-300">A├º├Áes</th>
                      </tr>
                    </thead>
                    <tbody>
                      {paiois.map((p) => (
                        <tr
                          key={p.id}
                          className="border-b border-[#f5f5f4] transition-colors hover:bg-[#fafaf9] dark:border-[#1a1a1a] dark:hover:bg-[#0a0a0a]"
                        >
                          <td className="py-3 font-medium text-[#1c1917] dark:text-white">
                            {p.nome}
                          </td>
                          <td className="py-3 text-[#57534e] dark:text-gray-400">
                            {p.localizacao ?? "ÔÇö"}
                          </td>
                          <td className="py-3 text-[#57534e] dark:text-gray-400">
                            {p.limiteMLE}
                          </td>
                          <td className="py-3 text-[#57534e] dark:text-gray-400">
                            {labelPerfilRisco(p.perfilRisco)}
                          </td>
                          <td className="py-3 text-[#57534e] dark:text-gray-400">
                            {p.mleAtual.toFixed(1)} / {p.limiteMLE} kg ({p.percentagemOcupacao.toFixed(0)}%)
                          </td>
                          <td className="py-3 text-[#57534e] dark:text-gray-400">
                            {p.estado}
                          </td>
                          <td className="py-3 flex flex-wrap gap-2">
                            <Link
                              href={`/armazem/${p.id}/editar`}
                              data-button
                              className="text-[#f97316] transition-[color] duration-200 hover:underline"
                            >
                              Editar
                            </Link>
                            <Link
                              href={`/armazem/${p.id}`}
                              data-button
                              className="text-[#f97316] transition-[color] duration-200 hover:underline"
                            >
                              Detalhes
                            </Link>
                            <Link
                              href={`/armazem/${p.id}/eliminar`}
                              data-button
                              className="text-red-600 transition-[color] duration-200 hover:underline dark:text-red-400"
                            >
                              Eliminar
                            </Link>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </>
            ) : null}
          </motion.div>
        </div>
      </main>
    </div>
  );
}

export default function GestaoPage() {
  return (
    <Suspense
      fallback={
        <div className="flex min-h-screen items-center justify-center bg-[#fafafa] dark:bg-[#0a0a0a]">
          <div className="h-8 w-8 animate-spin rounded-full border-2 border-[#f97316] border-t-transparent" />
        </div>
      }
    >
      <GestaoContent />
    </Suspense>
  );
}

"use client";

import { Suspense, useMemo } from "react";
import Link from "next/link";
import { useRouter, useSearchParams } from "next/navigation";
import { useQuery } from "@tanstack/react-query";
import { motion } from "framer-motion";
import type { ColumnDef } from "@tanstack/react-table";
import Navbar, { CONTENT_OFFSET_TOP } from "@/app/components/Navbar";
import { DataTable } from "@/app/components/ui/DataTable";
import { getToken } from "@/app/lib/auth";
import { safeParseJson } from "@/app/lib/api";
import { fadeInUp, transitionSmooth } from "@/app/lib/animations";
import { apiPath } from "@/app/lib/apiConfig";

const ITENS_POR_PAGINA = 20;
const inputClass =
  "rounded-xl border border-gray-300 bg-white px-3 py-2 text-gray-900 focus:border-[#f97316] focus:outline-none focus:ring-2 focus:ring-[#f97316]/20 dark:border-[#333] dark:bg-[#1a1a1a] dark:text-white";

type PaiolOption = { id: string; nome: string };

type EntradaRow = {
  id: number;
  paiolId: number;
  produtoId: number;
  quantidade: number;
  dataEntrada: string;
  funcionarioRegistouUserId?: string;
  numeroLote?: string;
  paiol?: { nome?: string; Nome?: string };
  produto?: { nome?: string; Nome?: string; nemPorUnidade?: number; NemPorUnidade?: number };
};

type SaidaRow = {
  id: number;
  paiolId: number;
  produtoId: number;
  quantidade: number;
  dataSaida: string;
  funcionarioRetirouUserId?: string;
  encomendaId?: number;
  paiol?: { nome?: string; Nome?: string };
  produto?: { nome?: string; Nome?: string };
};

/** Linha para a DataTable de entradas (valores planos para pesquisa/ordena├º├úo) */
type EntradaDisplay = {
  id: number;
  dataEntrada: string;
  paiolNome: string;
  produtoNome: string;
  quantidade: number;
  nem: string;
  registadoPor: string;
};

/** Linha para a DataTable de sa├¡das */
type SaidaDisplay = {
  id: number;
  dataSaida: string;
  paiolNome: string;
  produtoNome: string;
  quantidade: number;
  retiradoPor: string;
  encomendaId: number | null;
};

function entradasColumns(): ColumnDef<EntradaDisplay, unknown>[] {
  return [
    {
      accessorKey: "dataEntrada",
      header: "Data",
      cell: ({ getValue }) => (
        <span className="text-[#57534e] dark:text-gray-400">
          {new Date(getValue() as string).toLocaleString("pt-PT")}
        </span>
      ),
      enableSorting: true,
    },
    {
      accessorKey: "paiolNome",
      header: "Paiol",
      cell: ({ getValue }) => <span className="text-[#57534e] dark:text-gray-400">{getValue() as string}</span>,
      enableSorting: true,
    },
    {
      accessorKey: "produtoNome",
      header: "Produto",
      cell: ({ getValue }) => <span className="text-[#57534e] dark:text-gray-400">{getValue() as string}</span>,
      enableSorting: true,
    },
    {
      accessorKey: "quantidade",
      header: "Quantidade",
      cell: ({ getValue }) => <span className="text-[#57534e] dark:text-gray-400">{getValue() as number}</span>,
      enableSorting: true,
    },
    {
      accessorKey: "nem",
      header: "NEM (kg)",
      cell: ({ getValue }) => <span className="text-[#57534e] dark:text-gray-400">{getValue() as string}</span>,
      enableSorting: true,
    },
    {
      accessorKey: "registadoPor",
      header: "Registado por",
      cell: ({ getValue }) => <span className="text-[#57534e] dark:text-gray-400">{getValue() as string}</span>,
      enableSorting: true,
    },
  ];
}

function saidasColumns(
  buildUrl: (p: { tipo?: string; paiolId?: string; pagina?: number }) => string,
  tipo: string,
  paiolIdParam: string,
  pagina: number
): ColumnDef<SaidaDisplay, unknown>[] {
  return [
    {
      accessorKey: "dataSaida",
      header: "Data",
      cell: ({ getValue }) => (
        <span className="text-[#57534e] dark:text-gray-400">
          {new Date(getValue() as string).toLocaleString("pt-PT")}
        </span>
      ),
      enableSorting: true,
    },
    {
      accessorKey: "paiolNome",
      header: "Paiol",
      cell: ({ getValue }) => <span className="text-[#57534e] dark:text-gray-400">{getValue() as string}</span>,
      enableSorting: true,
    },
    {
      accessorKey: "produtoNome",
      header: "Produto",
      cell: ({ getValue }) => <span className="text-[#57534e] dark:text-gray-400">{getValue() as string}</span>,
      enableSorting: true,
    },
    {
      accessorKey: "quantidade",
      header: "Quantidade",
      cell: ({ getValue }) => <span className="text-[#57534e] dark:text-gray-400">{getValue() as number}</span>,
      enableSorting: true,
    },
    {
      accessorKey: "retiradoPor",
      header: "Retirado por",
      cell: ({ getValue }) => <span className="text-[#57534e] dark:text-gray-400">{getValue() as string}</span>,
      enableSorting: true,
    },
    {
      accessorKey: "encomendaId",
      header: "Encomenda",
      cell: ({ row }) => {
        const id = row.original.encomendaId;
        if (id == null) return <span className="text-[#57534e] dark:text-gray-400">ÔÇö</span>;
        const voltar = encodeURIComponent(buildUrl({ tipo, paiolId: paiolIdParam || undefined, pagina }));
        return (
          <Link
            href={`/encomendas/${id}?voltar=${voltar}`}
            className="text-[#f97316] hover:underline"
          >
            #{id}
          </Link>
        );
      },
      enableSorting: false,
    },
  ];
}

type MovimentosApiData = {
  paiois: PaiolOption[];
  entradas: EntradaRow[];
  saidas: SaidaRow[];
  nomesEntradas: Record<string, string>;
  nomesSaidas: Record<string, string>;
  totalRegistos: number;
};

async function fetchMovimentos(
  tipo: string,
  paiolIdParam: string,
  pagina: number,
  router: ReturnType<typeof useRouter>
): Promise<MovimentosApiData> {
  const token = getToken();
  if (!token) {
    router.replace("/login");
    throw new Error("N├úo autenticado");
  }
  const params = new URLSearchParams();
  if (tipo) params.set("tipo", tipo);
  if (paiolIdParam) params.set("paiolId", paiolIdParam);
  params.set("pagina", String(pagina));
  params.set("itensPorPagina", String(ITENS_POR_PAGINA));
  const res = await fetch(`${apiPath("api/paiol/movimentos")}?${params.toString()}`, {
    method: "GET",
    headers: { Authorization: `Bearer ${token}` },
  });
  if (res.status === 401) {
    router.replace("/login");
    throw new Error("N├úo autenticado");
  }
  if (!res.ok) {
    const text = await res.text();
    throw new Error(text || `Erro ${res.status}`);
  }
  const data = (await safeParseJson(res)) as Record<string, unknown> | null;
  if (!data) throw new Error("Resposta inv├ílida");
  const paioisRaw = (data.paiois ?? data.pai├│is ?? []) as Array<{ id?: number; Id?: number; nome?: string; Nome?: string }>;
  return {
    paiois: paioisRaw.map((p) => ({
      id: String(p.id ?? p.Id ?? ""),
      nome: String(p.nome ?? p.Nome ?? ""),
    })),
    entradas: (data.entradas as EntradaRow[]) ?? [],
    saidas: (data.saidas as SaidaRow[]) ?? [],
    nomesEntradas: (data.nomesUtilizadoresEntradas as Record<string, string>) ?? {},
    nomesSaidas: (data.nomesUtilizadoresSaidas as Record<string, string>) ?? {},
    totalRegistos: Number(data.totalRegistos) ?? 0,
  };
}

function MovimentosContent() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const tipo = searchParams.get("tipo") ?? "";
  const paiolIdParam = searchParams.get("paiolId") ?? "";
  const pagina = Math.max(1, parseInt(searchParams.get("pagina") ?? "1", 10) || 1);

  const { data: apiData, isLoading: loading, error: queryError, refetch } = useQuery({
    queryKey: ["movimentos", tipo, paiolIdParam, pagina],
    queryFn: () => fetchMovimentos(tipo, paiolIdParam, pagina, router),
    enabled: !!getToken(),
  });

  const paiois = apiData?.paiois ?? [];
  const entradas = apiData?.entradas ?? [];
  const saidas = apiData?.saidas ?? [];
  const nomesEntradas = apiData?.nomesEntradas ?? {};
  const nomesSaidas = apiData?.nomesSaidas ?? {};
  const totalRegistos = apiData?.totalRegistos ?? 0;
