                {totalPaginas > 1 && (
                  <p className="mt-6 text-sm text-[#57534e] dark:text-gray-400">
                    P├ígina do servidor:{" "}
                    <span className="font-medium text-[#1c1917] dark:text-white">
                      {(pagina - 1) * ITENS_POR_PAGINA + 1}ÔÇô
