            )}
            {!loading && !tipo && (
              <p className="mt-6 text-sm text-[#57534e] dark:text-gray-400">
                Selecione o tipo de movimento (Entradas ou Sa├¡das) e opcionalmente um paiol, depois clique em Ver.
              </p>
            )}
          </motion.div>
        </div>
      </main>
    </div>
  );
}

export default function MovimentosPage() {
  return (
