"use client";

import { useState, useEffect, useRef } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { motion } from "framer-motion";
import Navbar, { CONTENT_OFFSET_TOP } from "@/app/components/Navbar";
import MapaCoordenadas from "@/app/components/MapaCoordenadas";
import { getToken } from "@/app/lib/auth";
import {
  PERFIS_RISCO,
  ESTADOS_PAIOL,
  CARGOS_ACESSO_PAIOL,
  labelPerfilRisco,
  validarLimiteMLE,
  type PaiolDocumentoExtra,
  type CargoAcessoPaiol,
  type PerfilRiscoPaiol,
  type EstadoPaiol,
} from "@/app/lib/armazem";
import { fetchCreate } from "@/app/lib/paiolApi";
import { parseApiErrorBody } from "@/app/lib/apiErrors";
import { useToastStore } from "@/app/stores/useToastStore";
import { fadeInUp, transitionSmooth } from "@/app/lib/animations";

import { apiPath } from "@/app/lib/apiConfig";

const cardClass =
  "card-hover rounded-2xl border border-gray-200 bg-white p-6 shadow-sm dark:border-[#1f1f1f] dark:bg-[#111] sm:p-8";

const inputClass =
  "mt-2 w-full rounded-xl border border-gray-300 bg-white px-4 py-3 text-gray-900 placeholder-gray-400 focus:border-[#f97316] focus:outline-none focus:ring-2 focus:ring-[#f97316]/20 dark:border-[#333] dark:bg-[#1a1a1a] dark:text-white dark:placeholder-gray-500";

const labelClass = "block text-sm font-medium text-gray-700 dark:text-gray-300";

const btnPrimary =
  "data-button rounded-xl bg-[#f97316] px-5 py-2.5 text-sm font-semibold text-black transition-[opacity,background-color] duration-200 hover:opacity-90 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[#f97316]";

const btnSecondary =
  "data-button rounded-xl border border-gray-300 px-5 py-2.5 text-sm font-medium text-gray-700 transition-[border-color,background-color,color] duration-200 hover:bg-gray-50 dark:border-[#333] dark:text-gray-300 dark:hover:bg-[#1a1a1a]";

const FILE_ACCEPT = ".pdf,.jpg,.jpeg,.png";


export default function NovoPaiolPage() {
  const router = useRouter();
  const [mounted, setMounted] = useState(false);
  const [message, setMessage] = useState<{ type: "success" | "error"; text: string } | null>(null);
  const [form, setForm] = useState({
    nome: "",
    localizacao: "",
    coordenadasLat: "" as string | number,
    coordenadasLng: "" as string | number,
    limiteMLE: "" as string | number,
    perfilRisco: "1.3" as PerfilRiscoPaiol,
    estado: "Ativo" as EstadoPaiol,
    numeroLicenca: "",
    dataValidadeLicenca: "",
  });
  const [cargosAcesso, setCargosAcesso] = useState<CargoAcessoPaiol[]>([]);
  const [extras, setExtras] = useState<PaiolDocumentoExtra[]>([]);
  const submittingRef = useRef(false);

  const queryClient = useQueryClient();
  const token = getToken();

  const { data: createOptionsData } = useQuery({
    queryKey: ["armazem", "paiol", "create"],
    queryFn: () => fetchCreate(token!),
    staleTime: 5 * 60 * 1000,
    enabled: mounted && !!token,
  });

  const createOptions = createOptionsData
    ? {
        perfisRisco: createOptionsData.perfisRisco ?? [],
        estados: createOptionsData.estados ?? [],
        cargosDisponiveis: createOptionsData.cargosDisponiveis ?? [],
      }
    : null;

  const createMutation = useMutation({
    mutationFn: async (fd: FormData) => {
      const t = getToken();
      if (!t) throw new Error("Sess├úo expirada.");
      const res = await fetch(apiPath("api/paiol"), {
        method: "POST",
        headers: { Authorization: `Bearer ${t}` },
        body: fd,
      });
      if (res.status === 401) throw new Error("N├úo autenticado");
      if (res.status === 403) throw new Error("Sem permiss├úo para criar paiol (requer perfil Admin).");
      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        const parsed = parseApiErrorBody(err);
        throw new Error(parsed.message);
      }
      return res.json() as Promise<{ paiol?: { Id?: number; id?: number } }>;
    },
    onSuccess: (data) => {
      useToastStore.getState().show("Paiol criado com sucesso.", "success");
      queryClient.invalidateQueries({ queryKey: ["armazem", "gestao"] });
      queryClient.invalidateQueries({ queryKey: ["armazem", "paiol"] });
      const newId = data.paiol?.Id ?? data.paiol?.id;
      if (newId != null) router.push(`/armazem/${String(newId)}?criado=1`);
      else router.push("/armazem/gestao?criado=1");
    },
    onSettled: () => {
      submittingRef.current = false;
    },
  });

  useEffect(() => {
    setMounted(true);
  }, []);

  const toggleCargo = (c: CargoAcessoPaiol) => {
    setCargosAcesso((prev) =>
      prev.includes(c) ? prev.filter((x) => x !== c) : [...prev, c]
    );
  };

  const addDocExtra = () => {
    setExtras((e) => [...e, { id: `ex-${Date.now()}`, nome: "" }]);
  };

  const removeDocExtra = (id: string) => {
    setExtras((e) => e.filter((x) => x.id !== id));
  };

  const setExtraNome = (id: string, nome: string) => {
    setExtras((e) =>
      e.map((x) => (x.id === id ? { ...x, nome: nome.slice(0, 100) } : x))
    );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (submittingRef.current || createMutation.isPending) return;
    setMessage(null);
    if (!form.nome.trim()) {
      setMessage({ type: "error", text: "O nome do paiol ├® obrigat├│rio." });
      return;
    }
    if (form.nome.length > 200) {
      setMessage({ type: "error", text: "O nome n├úo pode exceder 200 caracteres." });
      return;
    }
    const limite = Number(form.limiteMLE);
    if (!validarLimiteMLE(limite)) {
      setMessage({ type: "error", text: "O limite MLE deve ser um valor positivo (ex.: 0.01 ou mais)." });
      return;
    }
    const latRaw = form.coordenadasLat === "" ? undefined : Number(form.coordenadasLat);
    const lngRaw = form.coordenadasLng === "" ? undefined : Number(form.coordenadasLng);
    const roundCoord = (n: number) => Math.round(n * 1e9) / 1e9;
    const lat = latRaw != null && !Number.isNaN(latRaw) ? roundCoord(latRaw) : undefined;
    const lng = lngRaw != null && !Number.isNaN(lngRaw) ? roundCoord(lngRaw) : undefined;
    if (!token) {
      router.replace("/login");
      return;
    }
    const fd = new FormData();
    fd.append("Paiol.Nome", form.nome.trim());
    fd.append("Paiol.Localizacao", form.localizacao.trim() || "");
    fd.append("Paiol.LimiteMLE", String(limite));
    fd.append("Paiol.PerfilRisco", form.perfilRisco);
    fd.append("Paiol.Estado", form.estado);
    if (form.dataValidadeLicenca?.trim()) fd.append("Paiol.DataValidadeLicenca", form.dataValidadeLicenca.trim());
    if (form.numeroLicenca?.trim()) fd.append("Paiol.NumeroLicenca", form.numeroLicenca.trim());
    if (lat != null) fd.append("Paiol.CoordenadasLat", String(lat));
    if (lng != null) fd.append("Paiol.CoordenadasLng", String(lng));
    const cargosParaEnviar = cargosAcesso.length > 0 ? cargosAcesso : ["Admin"];
    cargosParaEnviar.forEach((c) => fd.append("CargosAcesso", c));

    submittingRef.current = true;
    createMutation.mutate(fd, {
      onError: (err) => {
        setMessage({ type: "error", text: err instanceof Error ? err.message : "Erro de rede. Tente novamente." });
      },
    });
  };

  if (!mounted) return null;

  return (
    <div className="min-h-screen bg-[#f8f7f5] text-gray-900 dark:bg-[#0a0a0a] dark:text-white">
      <Navbar />

      <main
        className="relative px-6 pt-14 pb-10 sm:px-8"
        style={{ paddingTop: CONTENT_OFFSET_TOP }}
      >
        <div className="mx-auto max-w-3xl">
          <motion.div
            initial={fadeInUp.initial}
            animate={fadeInUp.animate}
            transition={transitionSmooth}
          >
            <h1 className="font-heading text-2xl tracking-tight text-gray-900 dark:text-white sm:text-3xl">
              Criar novo paiol
            </h1>
            <p className="mt-2 text-gray-600 dark:text-gray-400">
              Nome, localiza├º├úo, teto de seguran├ºa NEM (kg), perfil de risco, estado, licen├ºa PSP e cargos com acesso.
            </p>
          </motion.div>

          <form onSubmit={handleSubmit} className="mt-10 space-y-8">
            <motion.section
              initial={fadeInUp.initial}
              animate={fadeInUp.animate}
              transition={{ ...transitionSmooth, delay: 0.05 }}
              className={cardClass}
            >
              <h2 className="text-lg font-semibold text-gray-900 dark:text-white">
                Identifica├º├úo
              </h2>
              <div className="mt-4 space-y-4">
                <div>
                  <label htmlFor="nome" className={labelClass}>
                    Nome *
                  </label>
                  <input
                    id="nome"
                    type="text"
                    required
                    maxLength={200}
                    value={form.nome}
                    onChange={(e) => setForm((f) => ({ ...f, nome: e.target.value }))}
                    className={inputClass}
                    placeholder="Nome do paiol"
                  />
                </div>
                <div>
                  <label htmlFor="localizacao" className={labelClass}>
                    Localiza├º├úo (texto / morada)
                  </label>
                  <input
                    id="localizacao"
                    type="text"
                    maxLength={500}
                    value={form.localizacao}
                    onChange={(e) => setForm((f) => ({ ...f, localizacao: e.target.value }))}
                    className={inputClass}
                    placeholder="Localiza├º├úo ou morada"
                  />
                </div>
              </div>
            </motion.section>

            <motion.section
              initial={fadeInUp.initial}
              animate={fadeInUp.animate}
              transition={{ ...transitionSmooth, delay: 0.07 }}
              className={cardClass}
            >
              <h2 className="text-lg font-semibold text-gray-900 dark:text-white">
                Localiza├º├úo e mapa
              </h2>
              <p className="mt-1 text-sm text-gray-600 dark:text-gray-400">
                O mapa ser├í integrado acima; ao seleccionar um ponto, a latitude e a longitude ser├úo preenchidas automaticamente nos campos abaixo.
              </p>
              <div className="mt-4">
                <MapaCoordenadas
                  lat={form.coordenadasLat}
                  lng={form.coordenadasLng}
                  onLatChange={(v) => setForm((f) => ({ ...f, coordenadasLat: v }))}
                  onLngChange={(v) => setForm((f) => ({ ...f, coordenadasLng: v }))}
                  mapContainerId="mapa-paiol-novo"
                />
              </div>
            </motion.section>

            <motion.section
              initial={fadeInUp.initial}
              animate={fadeInUp.animate}
              transition={{ ...transitionSmooth, delay: 0.08 }}
              className={cardClass}
            >
              <h2 className="text-lg font-semibold text-gray-900 dark:text-white">
                Capacidade e licen├ºa
              </h2>
              <div className="mt-4 space-y-4">
                <div>
                  <label htmlFor="limiteMLE" className={labelClass}>
                    Teto de seguran├ºa NEM (kg) *
                  </label>
                  <input
                    id="limiteMLE"
                    type="number"
                    step="0.01"
                    min="0.01"
                    required
                    value={form.limiteMLE}
                    onChange={(e) => setForm((f) => ({ ...f, limiteMLE: e.target.value }))}
                    className={inputClass}
                    placeholder="Ex.: 100"
                  />
                </div>
                <div className="grid gap-4 sm:grid-cols-2">
                  <div>
                    <label htmlFor="perfilRisco" className={labelClass}>
                      Perfil de risco *
                    </label>
                    <select
                      id="perfilRisco"
                      value={form.perfilRisco}
                      onChange={(e) => setForm((f) => ({ ...f, perfilRisco: e.target.value as PerfilRiscoPaiol }))}
                      className={inputClass}
                    >
                      {PERFIS_RISCO.map((v) => (
                        <option key={v} value={v}>
                          {labelPerfilRisco(v)}
                        </option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label htmlFor="estado" className={labelClass}>
                      Estado *
                    </label>
                    <select
                      id="estado"
                      value={form.estado}
                      onChange={(e) => setForm((f) => ({ ...f, estado: e.target.value as EstadoPaiol }))}
                      className={inputClass}
                    >
                      {ESTADOS_PAIOL.map((v) => (
                        <option key={v} value={v}>
                          {v}
                        </option>
                      ))}
                    </select>
                  </div>
                </div>
                <div>
                  <label htmlFor="numeroLicenca" className={labelClass}>
                    N.┬║ licen├ºa
                  </label>
                  <input
                    id="numeroLicenca"
                    type="text"
                    maxLength={50}
                    value={form.numeroLicenca}
                    onChange={(e) => setForm((f) => ({ ...f, numeroLicenca: e.target.value }))}
                    className={inputClass}
                    placeholder="N├║mero da licen├ºa PSP"
                  />
                </div>
                <div>
                  <label htmlFor="dataValidadeLicenca" className={labelClass}>
                    Validade da licen├ºa
                  </label>
                  <input
                    id="dataValidadeLicenca"
                    type="date"
                    value={form.dataValidadeLicenca}
                    onChange={(e) => setForm((f) => ({ ...f, dataValidadeLicenca: e.target.value }))}
                    className={inputClass}
                  />
                </div>
              </div>
            </motion.section>

            <motion.section
              initial={fadeInUp.initial}
              animate={fadeInUp.animate}
              transition={{ ...transitionSmooth, delay: 0.1 }}
              className={cardClass}
            >
              <h2 className="text-lg font-semibold text-gray-900 dark:text-white">
                Cargos com acesso
              </h2>
              <p className="mt-1 text-sm text-gray-600 dark:text-gray-400">
                Seleccione os cargos (roles) que podem aceder a este paiol.
              </p>
              <div className="mt-4 flex flex-wrap gap-4">
                {CARGOS_ACESSO_PAIOL.map((c) => (
                  <label key={c} className="flex cursor-pointer items-center gap-2">
                    <input
                      type="checkbox"
                      checked={cargosAcesso.includes(c)}
                      onChange={() => toggleCargo(c)}
                      className="h-4 w-4 rounded border-gray-300 text-[#f97316] focus:ring-[#f97316]"
                    />
                    <span className="text-sm text-gray-700 dark:text-gray-300">{c}</span>
                  </label>
                ))}
              </div>
            </motion.section>

            <motion.section
              initial={fadeInUp.initial}
              animate={fadeInUp.animate}
              transition={{ ...transitionSmooth, delay: 0.12 }}
              className={cardClass}
            >
              <h2 className="text-lg font-semibold text-gray-900 dark:text-white">
                Documenta├º├úo
              </h2>
              <p className="mt-1 text-sm text-gray-600 dark:text-gray-400">
                Documentos extras (licen├ºas, plantas) com nome ├á escolha. Aceites: .pdf, .jpg, .jpeg, .png
              </p>
              <div className="mt-4 space-y-3">
                <button
                  type="button"
                  onClick={addDocExtra}
                  data-button
                  className="flex items-center gap-2 rounded-lg border border-dashed border-gray-300 px-3 py-2 text-sm font-medium text-gray-600 transition-[border-color,background-color,color] duration-200 hover:border-[#f97316] hover:bg-[#f97316]/5 hover:text-[#f97316] dark:border-[#444] dark:text-gray-400 dark:hover:border-[#f97316] dark:hover:text-[#f97316]"
                >
                  <span className="text-lg leading-none">+</span>
                  Adicionar documento
                </button>
                {extras.map((ex) => (
                  <div
                    key={ex.id}
                    className="flex flex-wrap items-end gap-3 rounded-lg border border-gray-200 p-3 dark:border-[#222]"
                  >
                    <div className="min-w-[200px] flex-1">
                      <label className="block text-sm font-medium text-gray-600 dark:text-gray-400">
                        Nome (m├íx. 100 caracteres)
                      </label>
                      <input
                        type="text"
                        maxLength={100}
                        value={ex.nome}
                        onChange={(e) => setExtraNome(ex.id, e.target.value)}
                        className={inputClass}
                        placeholder="Nome do documento"
                      />
                    </div>
                    <div className="min-w-[140px] flex-1">
                      <label className="block text-sm font-medium text-gray-600 dark:text-gray-400">
                        Ficheiro
                      </label>
                      <input
                        type="file"
                        accept={FILE_ACCEPT}
                        className={inputClass}
                        readOnly
                        tabIndex={-1}
                        aria-label="Ficheiro (em demonstra├º├úo n├úo ├® guardado)"
                      />
                    </div>
                    <button
                      type="button"
                      onClick={() => removeDocExtra(ex.id)}
                      className="rounded-lg px-3 py-2 text-sm font-medium text-red-600 transition-colors hover:bg-red-50 dark:hover:bg-red-950"
                    >
                      Remover
                    </button>
                  </div>
                ))}
              </div>
            </motion.section>

            {message && (
              <p
                className={`text-sm ${
                  message.type === "error" ? "text-red-600 dark:text-red-400" : "text-green-600 dark:text-green-400"
                }`}
              >
                {message.text}
              </p>
            )}

            <div className="flex flex-wrap gap-3">
              <button type="submit" className={btnPrimary} disabled={createMutation.isPending}>
                {createMutation.isPending ? "A guardarÔÇª" : "Guardar paiol"}
              </button>
              <Link href="/armazem/gestao" className={btnSecondary}>
                Cancelar
              </Link>
            </div>
          </form>
        </div>
      </main>
    </div>
  );
}

"use client";

import { useState, useEffect, Suspense, useMemo } from "react";
import Link from "next/link";
import { useRouter, useSearchParams } from "next/navigation";
import { useQuery } from "@tanstack/react-query";
import { motion } from "framer-motion";
import type { ColumnDef } from "@tanstack/react-table";
import Navbar, { CONTENT_OFFSET_TOP } from "@/app/components/Navbar";
import { DataTable } from "@/app/components/ui/DataTable";
import { getToken } from "@/app/lib/auth";
import { useUser } from "@/app/context/UserContext";
import { labelPerfilRisco } from "@/app/lib/armazem";
import { fadeInUp, transitionSmooth } from "@/app/lib/animations";

import { apiPath } from "@/app/lib/apiConfig";

/** Paiol com ocupa├º├úo (vindo da API) para a lista do Armaz├®m */
type PaiolComOcupacao = {
  id: string;
  nome: string;
  localizacao?: string;
  perfilRisco: string;
  estado: string;
  percentagemOcupacao: number;
};

function armazemColumns(): ColumnDef<PaiolComOcupacao, unknown>[] {
  return [
    {
      accessorKey: "nome",
      header: "Nome",
      cell: ({ row }) => (
        <Link
          href={`/armazem/${row.original.id}/conteudo`}
          className="text-[#f97316] transition-[color] duration-200 hover:underline"
        >
          {row.original.nome}
        </Link>
      ),
      enableSorting: true,
    },
    {
      accessorKey: "localizacao",
      header: "Localiza├º├úo (cidade)",
      cell: ({ getValue }) => (
        <span className="text-[#57534e] dark:text-gray-400">{getValue() as string ?? "ÔÇö"}</span>
      ),
      enableSorting: true,
    },
    {
      accessorKey: "perfilRisco",
      header: "Perfil de risco",
      cell: ({ getValue }) => (
        <span className="text-[#57534e] dark:text-gray-400">{labelPerfilRisco(getValue() as string)}</span>
      ),
      enableSorting: true,
    },
    {
      accessorKey: "percentagemOcupacao",
      header: "Ocupa├º├úo",
      cell: ({ row }) => {
        const pct = Math.min(100, Math.max(0, row.original.percentagemOcupacao));
        return (
          <div className="flex min-w-[120px] max-w-[200px] items-center gap-2">
            <div
              className="h-2 flex-1 overflow-hidden rounded-full bg-gray-200 dark:bg-[#333]"
              role="progressbar"
              aria-valuenow={pct}
              aria-valuemin={0}
              aria-valuemax={100}
              aria-label={`Ocupa├º├úo do paiol: ${pct.toFixed(0)}%`}
            >
              <div
                className="h-full rounded-full bg-[#f97316] transition-[width] duration-300"
                style={{ width: `${pct}%` }}
              />
            </div>
            <span className="shrink-0 text-xs text-[#57534e] dark:text-gray-400">{pct.toFixed(0)}%</span>
          </div>
        );
      },
      enableSorting: true,
    },
    {
      accessorKey: "estado",
      header: "Estado",
      cell: ({ getValue }) => (
        <span className="text-[#57534e] dark:text-gray-400">{getValue() as string}</span>
      ),
      enableSorting: true,
    },
    {
      id: "acoes",
      header: "A├º├Áes",
      cell: ({ row }) => (
        <Link
          href={`/armazem/${row.original.id}`}
          data-button
          className="text-[#f97316] transition-[color] duration-200 hover:underline"
        >
          Detalhes
        </Link>
      ),
      enableSorting: false,
    },
  ];
}

const btnPrimary =
  "data-button rounded-xl bg-[#f97316] px-4 py-2 text-sm font-semibold text-black transition-[opacity,background-color] duration-200 hover:opacity-90 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[#f97316]";

const btnSecondary =
  "data-button rounded-xl border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 transition-[border-color,background-color,color] duration-200 hover:bg-gray-50 dark:border-[#333] dark:text-gray-300 dark:hover:bg-[#1a1a1a]";

function mapApiToPaiolComOcupacao(item: Record<string, unknown>): PaiolComOcupacao {
  const p = (item.Paiol ?? item.paiol ?? {}) as Record<string, unknown>;
  const pct = Number(item.PercentagemOcupacao ?? item.percentagemOcupacao ?? 0);
  return {
    id: String(p.Id ?? p.id ?? ""),
    nome: String(p.Nome ?? p.nome ?? "").trim() || "ÔÇö",
    localizacao: (p.Localizacao ?? p.localizacao) as string | undefined,
    perfilRisco: String(p.PerfilRisco ?? p.perfilRisco ?? ""),
    estado: String(p.Estado ?? p.estado ?? ""),
    percentagemOcupacao: Number.isFinite(pct) ? pct : 0,
  };
}

function ArmazemContent() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const { user } = useUser();
  const permissions = user?.permissions ?? [];
  const canGerirArmazem = permissions.includes("armazem.gerir");
  const eliminado = searchParams.get("eliminado") === "1";
  const columns = useMemo(() => armazemColumns(), []);

  const {
    data: paiois = [],
    isLoading: loading,
    isRefetching,
    error: queryError,
  } = useQuery({
    queryKey: ["armazem", "paiol"],
    queryFn: async (): Promise<PaiolComOcupacao[]> => {
      const token = getToken();
      if (!token) {
        router.replace("/login");
        throw new Error("Sess├úo expirada. Fa├ºa login novamente.");
      }
      const res = await fetch(apiPath("api/paiol"), {
        headers: { Authorization: `Bearer ${token}` },
      });
      if (res.status === 401) {
        router.replace("/login");
        throw new Error("Sess├úo expirada. Fa├ºa login novamente.");
      }
      if (!res.ok) throw new Error(res.status === 404 ? "N├úo encontrado" : `Erro ${res.status}`);
      const data = (await res.json()) as unknown;
      const list = Array.isArray(data) ? data : [];
      return list.map((item: Record<string, unknown>) => mapApiToPaiolComOcupacao(item));
    },
    staleTime: 30 * 1000,
    retry: 3,
    enabled: !!getToken(),
  });

  const error =
    queryError instanceof Error
      ? queryError.message === "Failed to fetch"
        ? "Falha de rede. Verifique se a API est├í a correr (NEXT_PUBLIC_API_URL) e se CORS permite pedidos do frontend."
        : queryError.message
      : queryError
        ? "Erro ao carregar pai├│is."
        : null;

  const alerta = eliminado ? "Paiol eliminado com sucesso." : null;

  return (
    <div className="min-h-screen bg-[#f8f7f5] text-[#1c1917] dark:bg-[#0a0a0a] dark:text-white">
      <Navbar />

      <main
        className="relative px-6 pt-14 pb-10 sm:px-8"
        style={{ paddingTop: CONTENT_OFFSET_TOP }}
      >
        <div className="mx-auto max-w-6xl">
          <motion.div
            initial={fadeInUp.initial}
            animate={fadeInUp.animate}
            transition={transitionSmooth}
            className="flex flex-col gap-5 sm:flex-row sm:flex-wrap sm:items-center sm:justify-between"
          >
            <div>
              <h1 className="font-heading text-2xl tracking-tight text-[#1c1917] dark:text-white sm:text-3xl">
                Armaz├®m
              </h1>
              <p className="mt-1 flex items-center gap-2 text-[#57534e] dark:text-gray-400">
                Pai├│is com acesso, ocupa├º├úo MLE e liga├º├Áes para stock e movimentos.
                {isRefetching && !loading && (
                  <span className="inline-flex items-center gap-1.5 text-xs text-[#78716c] dark:text-gray-500">
                    <span className="h-1.5 w-1.5 shrink-0 animate-pulse rounded-full bg-[#f97316]" />
                    A atualizar
                  </span>
                )}
              </p>
            </div>
            <div className="flex flex-wrap gap-2">
              <Link href="/armazem/stock" className={btnSecondary}>
                Stock
              </Link>
              {canGerirArmazem && (
                <Link href="/armazem/movimentos" className={btnSecondary}>
                  Movimentos
                </Link>
              )}
              {canGerirArmazem && (
                <Link href="/armazem/gestao" className={btnPrimary}>
                  Gest├úo de Pai├│is
                </Link>
              )}
            </div>
          </motion.div>

          {alerta && (
            <motion.p
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={transitionSmooth}
              className="mt-5 rounded-xl bg-green-100 px-4 py-3 text-sm text-green-800 dark:bg-green-900/30 dark:text-green-400"
            >
              {alerta}
            </motion.p>
          )}

          {error && (
            <motion.p
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={transitionSmooth}
              className="mt-5 rounded-xl bg-red-100 px-4 py-3 text-sm text-red-800 dark:bg-red-900/30 dark:text-red-400"
            >
              {error}
            </motion.p>
          )}

          <motion.div
            initial={fadeInUp.initial}
            animate={fadeInUp.animate}
            transition={{ ...transitionSmooth, delay: 0.05 }}
            className="card-hover mt-10 rounded-2xl border border-[#e7e5e4] bg-white p-5 shadow-[0_1px_3px_rgba(0,0,0,0.06)] dark:border-[#1f1f1f] dark:bg-[#111] dark:shadow-none sm:p-6"
          >
            {loading ? (
              <div className="flex flex-col items-center justify-center gap-3 py-12 text-[#57534e] dark:text-gray-400">
                <div className="h-8 w-8 animate-spin rounded-full border-2 border-[#f97316] border-t-transparent" />
                <span>A carregar pai├│isÔÇª</span>
              </div>
            ) : paiois.length === 0 ? (
              <div className="rounded-xl border border-dashed border-[#e7e5e4] bg-[#fafaf9] py-12 text-center dark:border-[#333] dark:bg-[#0a0a0a]">
                <p className="text-[#57534e] dark:text-gray-400">
                  N├úo tem acesso a nenhum paiol ou ainda n├úo existem pai├│is. Os administradores podem criar pai├│is em Gest├úo de Pai├│is.
                </p>
                {canGerirArmazem && (
                  <Link href="/armazem/gestao" className={btnPrimary + " mt-4 inline-block"}>
                    Ir para Gest├úo de Pai├│is
                  </Link>
                )}
              </div>
            ) : (
              <DataTable
                columns={columns}
                data={paiois}
                pageSize={10}
                searchPlaceholder="Pesquisar pai├│isÔÇª"
                emptyMessage="N├úo tem acesso a nenhum paiol ou ainda n├úo existem pai├│is."
                noResultsMessage="Nenhum paiol encontrado para a pesquisa."
              />
            )}
          </motion.div>
        </div>
      </main>
    </div>
  );
}

export default function ArmazemPage() {
  return (
    <Suspense
      fallback={
        <div className="flex min-h-screen items-center justify-center bg-[#fafafa] dark:bg-[#0a0a0a]">
          <div className="h-8 w-8 animate-spin rounded-full border-2 border-[#f97316] border-t-transparent" />
        </div>
      }
    >
      <ArmazemContent />
    </Suspense>
  );
}

