function parsePaiolProdutoIds(paiolId: string, produtoId: string): { paiolNum: number; produtoNum: number } | null {
  const pidPaiol = parseInt(String(paiolId).trim(), 10);
  const m = String(paiolId).trim().match(/^D(\d+)$/i);
  const paiolNum = m ? parseInt(m[1], 10) : pidPaiol;
  const produtoNum = parseInt(String(produtoId).trim(), 10);
  if (Number.isNaN(paiolNum) || paiolNum < 1 || Number.isNaN(produtoNum) || produtoNum < 1) return null;
  return { paiolNum, produtoNum };
}

function RegistarSaidaContent() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const queryClient = useQueryClient();
  const paiolId = searchParams.get("paiolId") ?? "";
  const produtoId = searchParams.get("produtoId") ?? "";
  const { user } = useUser();
  const [mounted, setMounted] = useState(false);
  const [message, setMessage] = useState<{ type: "success" | "error"; text: string } | null>(null);
  const [quantidade, setQuantidade] = useState("");
  const token = getToken();
  const ids = parsePaiolProdutoIds(paiolId, produtoId);
  const submittingRef = useRef(false);

  const { data: formFromApi, isLoading: loadingForm } = useQuery({
    queryKey: ["armazem", "saida-paiol", "registar", ids?.paiolNum, ids?.produtoNum],
    queryFn: async (): Promise<{ paiolNome: string; produtoNome: string; stockDisponivel: number }> => {
      if (!token || !ids) throw new Error("Par├ómetros em falta");
      const res = await fetch(`${apiPath("api/saida-paiol/registar")}?paiolId=${ids.paiolNum}&produtoId=${ids.produtoNum}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      if (res.status === 401) {
        router.replace("/login");
        throw new Error("N├úo autenticado");
      }
      if (res.status === 403 || res.status === 404 || !res.ok) return { paiolNome: "", produtoNome: "", stockDisponivel: 0 };
      const data = (await res.json()) as Record<string, unknown>;
      const nomePaiol = (data.paiolNome ?? data.PaiolNome) as string | undefined;
      const nomeProduto = (data.produtoNome ?? data.ProdutoNome) as string | undefined;
      const stock = data.stockDisponivel ?? data.StockDisponivel;
      const stockNum = typeof stock === "number" ? stock : Number(stock);
      return {
        paiolNome: String(nomePaiol ?? ""),
        produtoNome: String(nomeProduto ?? ""),
        stockDisponivel: Number.isFinite(stockNum) ? Math.max(0, stockNum) : 0,
      };
    },
    staleTime: 30 * 1000,
    enabled: mounted && !!token && !!ids,
  });

  const registarMutation = useMutation({
    mutationFn: async (body: { PaiolId: number; ProdutoId: number; Quantidade: number }) => {
      const res = await fetch(apiPath("api/saida-paiol/registar"), {
        method: "POST",
        headers: { "Content-Type": "application/json", Authorization: `Bearer ${token!}` },
        body: JSON.stringify(body),
      });
      if (res.status === 401) {
        router.replace("/login");
        throw new Error("N├úo autenticado");
      }
      if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        throw new Error(parseApiErrorBody(data).message);
      }
      return safeParseJson(res);
    },
    onSuccess: () => {
      useToastStore.getState().show("Sa├¡da registada com sucesso.", "success");
      queryClient.invalidateQueries({ queryKey: ["armazem"] });
      queryClient.invalidateQueries({ queryKey: ["armazem", paiolId] });
      router.push(`/armazem/${paiolId}/conteudo`);
    },
    onError: (err) => {
      setMessage({
        type: "error",
        text: err instanceof Error ? err.message : "Erro ao registar sa├¡da. Verifique se a API est├í a correr.",
      });
    },
    onSettled: () => {
      submittingRef.current = false;
    },
  });

  useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-[#fafafa] dark:bg-[#0a0a0a]">
        <div className="h-8 w-8 animate-spin rounded-full border-2 border-[#f97316] border-t-transparent" />
      </div>
    );
  }

  const stockDisponivel = formFromApi?.stockDisponivel ?? 0;
  const paiolNome = formFromApi?.paiolNome ?? "";
  const produtoNome = formFromApi?.produtoNome ?? "";
  const temDadosParaForm = formFromApi != null && (formFromApi.paiolNome || formFromApi.produtoNome);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (submittingRef.current || registarMutation.isPending) return;
    setMessage(null);
    if (!paiolId || !produtoId || !ids) {
      setMessage({ type: "error", text: "Paiol e produto s├úo obrigat├│rios. Aceda a partir do conte├║do do paiol." });
      return;
    }
    const qty = Number(quantidade);
    if (!Number.isFinite(qty) || qty <= 0) {
      setMessage({ type: "error", text: "A quantidade deve ser um n├║mero positivo." });
      return;
    }
    if (qty > stockDisponivel) {
      setMessage({ type: "error", text: `A quantidade n├úo pode exceder o stock dispon├¡vel (${stockDisponivel}).` });
      return;
    }
    if (!token) {
      router.replace("/login");
      return;
    }
    submittingRef.current = true;
    registarMutation.mutate({
      PaiolId: ids.paiolNum,
      ProdutoId: ids.produtoNum,
      Quantidade: Number(qty),
    });
  };

  if (!paiolId || !produtoId) {
    return (
      <div className="min-h-screen bg-[#f8f7f5] dark:bg-[#0a0a0a]">
        <Navbar />
        <main style={{ paddingTop: CONTENT_OFFSET_TOP }} className="p-8">
          <p className="text-gray-600 dark:text-gray-400">
            Deve indicar o paiol e o produto. Aceda a partir do conte├║do do paiol e clique em &quot;Retirar&quot; na linha do produto.
          </p>
          <Link href="/armazem" className="mt-5 inline-block text-[#f97316] hover:underline">
            ÔåÉ Voltar ao Armaz├®m
          </Link>
        </main>
      </div>
    );
  }

  if (!temDadosParaForm) {
    return (
      <div className="min-h-screen bg-[#f8f7f5] dark:bg-[#0a0a0a]">
        <Navbar />
        <main style={{ paddingTop: CONTENT_OFFSET_TOP }} className="p-8">
          {loadingForm ? (
            <div className="flex justify-center py-12">
              <div className="h-8 w-8 animate-spin rounded-full border-2 border-[#f97316] border-t-transparent" />
            </div>
          ) : (
            <>
              <p className="text-gray-600 dark:text-gray-400">Paiol ou produto n├úo encontrado. Aceda a partir do conte├║do do paiol.</p>
              <Link href="/armazem" className="mt-5 inline-block text-[#f97316] hover:underline">
                ÔåÉ Voltar ao Armaz├®m
              </Link>
            </>
          )}
        </main>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#f8f7f5] text-gray-900 dark:bg-[#0a0a0a] dark:text-white">
      <Navbar />

      <main
        className="relative px-6 pt-14 pb-10 sm:px-8"
        style={{ paddingTop: CONTENT_OFFSET_TOP }}
      >
        <div className="mx-auto max-w-2xl">
          <motion.div
            initial={fadeInUp.initial}
            animate={fadeInUp.animate}
            transition={transitionSmooth}
          >
            <h1 className="font-heading text-2xl tracking-tight text-gray-900 dark:text-white sm:text-3xl">
              Registar sa├¡da
            </h1>
            <p className="mt-2 text-gray-600 dark:text-gray-400">
              Paiol: <strong>{paiolNome}</strong>. Produto: <strong>{produtoNome}</strong>.
            </p>
            <p className="mt-1 text-gray-600 dark:text-gray-400">
              Stock dispon├¡vel: <strong>{stockDisponivel}</strong> unidades.
            </p>
          </motion.div>

          {stockDisponivel <= 0 ? (
            <motion.section
              initial={fadeInUp.initial}
              animate={fadeInUp.animate}
              transition={{ ...transitionSmooth, delay: 0.05 }}
              className={`mt-8 ${cardClass}`}
            >
              <p className="text-gray-600 dark:text-gray-400">
                N├úo h├í stock dispon├¡vel para este produto neste paiol. N├úo ├® poss├¡vel registar sa├¡da.
              </p>
              <Link href={`/armazem/${paiolId}/conteudo`} className={btnSecondary + " mt-4 inline-block"}>
                Voltar ao conte├║do do paiol
              </Link>
            </motion.section>
          ) : (
            <form onSubmit={handleSubmit}>
              <motion.section
                initial={fadeInUp.initial}
                animate={fadeInUp.animate}
                transition={{ ...transitionSmooth, delay: 0.05 }}
                className={`mt-8 ${cardClass}`}
              >
                <div>
                  <label htmlFor="quantidade" className={labelClass}>
                    Quantidade *
                  </label>
                  <input
                    id="quantidade"
                    type="number"
                    step="1"
                    min="1"
                    max={stockDisponivel}
                    required
                    value={quantidade}
                    onChange={(e) => setQuantidade(e.target.value)}
                    className={inputClass}
                    placeholder={`M├íx. ${stockDisponivel}`}
                  />
                  <p className="mt-1 text-sm text-gray-500 dark:text-gray-400">
                    M├íximo: {stockDisponivel} unidades.
                  </p>
                </div>
                {message && (
                  <p className={`mt-4 text-sm ${message.type === "error" ? "text-red-600 dark:text-red-400" : "text-green-600 dark:text-green-400"}`}>
                    {message.text}
                  </p>
                )}
                <div className="mt-6 flex flex-wrap gap-3">
                  <button type="submit" className={btnPrimary} disabled={registarMutation.isPending}>
                    {registarMutation.isPending ? "A registarÔÇª" : "Registar sa├¡da"}
                  </button>
                  <Link href={`/armazem/${paiolId}/conteudo`} className={btnSecondary}>
                    Cancelar
                  </Link>
                </div>
              </motion.section>
            </form>
          )}

          <p className="mt-8">
            <Link href={`/armazem/${paiolId}/conteudo`} className="text-[#f97316] hover:underline">
              ÔåÉ Voltar ao conte├║do do paiol
            </Link>
          </p>
        </div>
      </main>
    </div>
  );
}

