"use client";

import { useState, useEffect, useRef } from "react";
import Link from "next/link";
import { useParams, useRouter } from "next/navigation";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { motion } from "framer-motion";
import Navbar, { CONTENT_OFFSET_TOP } from "@/app/components/Navbar";
import { getToken } from "@/app/lib/auth";
import { useToastStore } from "@/app/stores/useToastStore";
import { useUser } from "@/app/context/UserContext";
import { fetchEncomendaDetalhe, putEncomenda } from "@/app/lib/encomendasApi";
import { fetchList } from "@/app/lib/produtosApi";
import { fadeInUp, transitionSmooth } from "@/app/lib/animations";

const inputClass =
  "rounded-xl border border-gray-300 bg-white px-3 py-2 text-gray-900 dark:border-[#333] dark:bg-[#1a1a1a] dark:text-white";

const labelClass = "block text-sm font-medium text-gray-700 dark:text-gray-300";

const btnPrimary =
  "data-button rounded-xl bg-[#f97316] px-4 py-2 text-sm font-semibold text-black transition-[opacity,background-color] duration-200 hover:opacity-90 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[#f97316]";

const btnSecondary =
  "data-button rounded-xl border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 dark:border-[#333] dark:text-gray-300 dark:hover:bg-[#1a1a1a]";

const MIN_QUANTIDADE = 0.0001;

type ItemEdit = { produtoId: string; produtoNome: string; quantidade: number };

function mapApiToForm(data: { encomenda: Record<string, unknown> }): {
  id: string;
  clienteId: string;
  clienteNome: string;
  estado: string;
  dataEntrega: string;
  observacoes: string;
  itens: ItemEdit[];
} {
  const e = data.encomenda;
  const get = (k: string) => e[k] ?? e[k.charAt(0).toUpperCase() + k.slice(1)];
  const itensRaw = (get("itens") ?? get("Itens")) as Array<Record<string, unknown>> | undefined;
  const itens: ItemEdit[] = (itensRaw ?? []).map((i) => {
    const gi = (key: string) => i[key] ?? i[key.charAt(0).toUpperCase() + key.slice(1)];
    const prod = gi("produto") ?? gi("Produto");
    const prodObj = prod && typeof prod === "object" ? (prod as Record<string, unknown>) : null;
    const nome = prodObj ? String(prodObj.nome ?? prodObj.Nome ?? "") : "";
    return {
      produtoId: String(gi("produtoId") ?? gi("ProdutoId") ?? ""),
      produtoNome: nome,
      quantidade: Number(gi("quantidadePedida") ?? gi("QuantidadePedida") ?? 0),
    };
  });
  const cliente = get("cliente") ?? get("Cliente");
  const clienteObj = cliente && typeof cliente === "object" ? (cliente as Record<string, unknown>) : null;
  const dataEntregaRaw = get("dataEntrega") ?? get("DataEntrega");
  const dataEntregaStr =
    dataEntregaRaw != null
      ? typeof dataEntregaRaw === "string"
        ? dataEntregaRaw.slice(0, 10)
        : new Date(dataEntregaRaw as string).toISOString().slice(0, 10)
      : "";
  return {
    id: String(get("id") ?? get("Id") ?? ""),
    clienteId: String(get("clienteId") ?? get("ClienteId") ?? ""),
    clienteNome: clienteObj ? String(clienteObj.nome ?? clienteObj.Nome ?? "") : "",
    estado: String(get("estado") ?? get("Estado") ?? "Pendente"),
    dataEntrega: dataEntregaStr,
    observacoes: String(get("observacoes") ?? get("Observacoes") ?? ""),
    itens,
  };
}

export default function EditarEncomendaPage() {
  const params = useParams();
  const router = useRouter();
  const queryClient = useQueryClient();
  const id = params.id as string;
  const numId = parseInt(id, 10);
  const validId = !Number.isNaN(numId);

  const { user } = useUser();
  const userId = user?.id ?? user?.email ?? null;
  const canGerirEncomendas = (user?.permissions ?? []).includes("encomendas.gerir");
  const [dataEntrega, setDataEntrega] = useState("");
  const [observacoes, setObservacoes] = useState("");
  const [itens, setItens] = useState<ItemEdit[]>([]);
  const [novoProdutoId, setNovoProdutoId] = useState("");
  const [novaQuantidade, setNovaQuantidade] = useState("");
  const [erro, setErro] = useState<string | null>(null);
  const submittingRef = useRef(false);

  const { data: editData, isLoading: loadingEncomenda, error: queryError } = useQuery({
    queryKey: ["encomendas", id, "edit"],
    queryFn: async () => {
      const token = getToken();
      if (!token) throw new Error("Sess├úo expirada.");
      return fetchEncomendaDetalhe(token, numId);
    },
    staleTime: 60 * 1000,
    retry: 1,
    retryDelay: 800,
    enabled: validId && !!getToken(),
  });

  const { data: produtosData, isLoading: loadingProdutos } = useQuery({
    queryKey: ["produtos", "list"],
    queryFn: async () => {
      const token = getToken();
      if (!token) throw new Error("Sess├úo expirada.");
      return fetchList(token, {});
    },
    staleTime: 60 * 1000,
    enabled: validId && !!getToken(),
  });

  const encomendaForm = editData ? mapApiToForm(editData) : null;
  const produtos = (produtosData?.items ?? []) as Array<{ id?: number; Id?: number; nome?: string; Nome?: string }>;
  const produtosSorted = [...produtos].sort((a, b) =>
    String(a.nome ?? a.Nome ?? "").localeCompare(String(b.nome ?? b.Nome ?? ""))
  );
  const produtosJaNaEncomenda = new Set(itens.map((i) => i.produtoId));

  useEffect(() => {
    if (encomendaForm) {
      setDataEntrega(encomendaForm.dataEntrega);
      setObservacoes(encomendaForm.observacoes);
      setItens(encomendaForm.itens);
    }
  }, [encomendaForm?.id]);

  const mutation = useMutation({
    mutationFn: async (payload: { dataEntrega: string; observacoes: string; itens: ItemEdit[] }) => {
      const token = getToken();
      if (!token) throw new Error("Sess├úo expirada.");
      await putEncomenda(token, numId, {
        dataEntrega: payload.dataEntrega.trim() || null,
        observacoes: payload.observacoes.trim() || null,
        itens: payload.itens.map((i) => ({ produtoId: parseInt(i.produtoId, 10), quantidade: i.quantidade })),
      });
    },
    onSuccess: () => {
      useToastStore.getState().show("Encomenda atualizada com sucesso.", "success");
      queryClient.invalidateQueries({ queryKey: ["encomendas"] });
      queryClient.invalidateQueries({ queryKey: ["encomendas", id] });
      router.push(`/encomendas/${id}?editada=1`);
    },
    onError: (err: Error) => setErro(err.message || "Erro ao guardar."),
    onSettled: () => {
      submittingRef.current = false;
    },
  });

  const podeEditar =
    encomendaForm &&
    (encomendaForm.estado === "Pendente" || encomendaForm.estado === "Aceite") &&
    (canGerirEncomendas || !!userId);

  if (loadingEncomenda && validId) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-[#fafafa] dark:bg-[#0a0a0a]">
        <div className="h-8 w-8 animate-spin rounded-full border-2 border-[#f97316] border-t-transparent" />
      </div>
    );
  }

  if (queryError || !encomendaForm) {
    return (
      <div className="min-h-screen bg-[#f8f7f5] dark:bg-[#0a0a0a]">
        <Navbar />
        <main style={{ paddingTop: CONTENT_OFFSET_TOP }} className="p-8">
          {queryError && (
            <p className="mb-4 rounded-xl bg-red-100 px-4 py-3 text-sm text-red-800 dark:bg-red-900/30 dark:text-red-400">
              {queryError instanceof Error ? queryError.message : "Erro ao carregar."}
            </p>
          )}
          {!queryError && <p className="text-gray-600 dark:text-gray-400">Encomenda n├úo encontrada.</p>}
          <Link href="/encomendas" className="mt-4 inline-block text-[#f97316] hover:underline">
            ÔåÉ Voltar ├ás Encomendas
          </Link>
        </main>
      </div>
    );
  }

  if (!podeEditar) {
    return (
      <div className="min-h-screen bg-[#f8f7f5] dark:bg-[#0a0a0a]">
        <Navbar />
        <main style={{ paddingTop: CONTENT_OFFSET_TOP }} className="p-8">
          <p className="text-gray-600 dark:text-gray-400">
            Apenas o criador da encomenda ou um administrador podem edit├í-la. Encomendas s├│ podem ser editadas nos estados Pendente ou Aceite.
          </p>
          <Link href={`/encomendas/${id}`} className="mt-4 inline-block text-[#f97316] hover:underline">
            ÔåÉ Voltar aos detalhes
          </Link>
        </main>
      </div>
    );
  }

  if (encomendaForm.estado !== "Pendente" && encomendaForm.estado !== "Aceite") {
    router.replace(`/encomendas/${id}?erro=1`);
    return null;
  }

  const setQuantidade = (produtoId: string, quantidade: number) => {
    setItens((prev) => prev.map((i) => (i.produtoId === produtoId ? { ...i, quantidade } : i)));
  };

  const removerItem = (produtoId: string) => {
    setItens((prev) => prev.filter((i) => i.produtoId !== produtoId));
  };

  const adicionarItem = (e: React.FormEvent) => {
    e.preventDefault();
    setErro(null);
    const pr = produtosSorted.find((p) => String(p.id ?? p.Id) === novoProdutoId);
    const q = parseFloat(novaQuantidade.replace(",", "."));
    if (!pr || Number.isNaN(q) || q < MIN_QUANTIDADE) {
      setErro("Selecione um produto e uma quantidade v├ílida (m├¡n. 0,0001).");
      return;
    }
    const existente = itens.find((i) => i.produtoId === novoProdutoId);
    if (existente) {
      setQuantidade(novoProdutoId, existente.quantidade + q);
    } else {
      setItens((prev) => [
        ...prev,
        {
          produtoId: String(pr.id ?? pr.Id),
          produtoNome: String(pr.nome ?? pr.Nome ?? ""),
          quantidade: q,
        },
      ]);
    }
    setNovoProdutoId("");
    setNovaQuantidade("");
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (submittingRef.current) return;
    setErro(null);
    const validos = itens.filter((i) => i.quantidade >= MIN_QUANTIDADE);
    if (validos.length === 0) {
      setErro("A encomenda tem de ter pelo menos um item com quantidade positiva.");
      return;
    }
    submittingRef.current = true;
    mutation.mutate({ dataEntrega, observacoes, itens: validos });
  };

  const submitting = mutation.isPending;
  const clienteNome = encomendaForm.clienteNome || encomendaForm.clienteId;

  return (
    <div className="min-h-screen bg-[#f8f7f5] text-[#1c1917] dark:bg-[#0a0a0a] dark:text-white">
      <Navbar />

      <main className="relative px-6 pt-14 pb-10 sm:px-8" style={{ paddingTop: CONTENT_OFFSET_TOP }}>
        <div className="mx-auto max-w-3xl">
          <motion.div initial={fadeInUp.initial} animate={fadeInUp.animate} transition={transitionSmooth}>
            <h1 className="font-heading text-2xl tracking-tight sm:text-3xl">Editar encomenda</h1>
            <p className="mt-1 text-[#57534e] dark:text-gray-400">
              Encomenda #{id} ┬À Cliente: {clienteNome} ┬À Estado: {encomendaForm.estado}
            </p>
          </motion.div>

          {erro && (
            <p className="mt-6 rounded-xl bg-red-100 px-4 py-3 text-sm text-red-800 dark:bg-red-900/30 dark:text-red-400">
              {erro}
            </p>
          )}

          <form onSubmit={handleSubmit}>
            <motion.div
              initial={fadeInUp.initial}
              animate={fadeInUp.animate}
              transition={{ ...transitionSmooth, delay: 0.05 }}
              className="card-hover mt-10 rounded-2xl border border-[#e7e5e4] bg-white p-6 dark:border-[#1f1f1f] dark:bg-[#111] sm:p-8"
            >
              <h2 className="text-lg font-semibold text-gray-900 dark:text-white">Data e observa├º├Áes</h2>
              <div className="mt-4 space-y-4">
                <div>
                  <label htmlFor="dataEntrega" className={labelClass}>
                    Data de entrega
                  </label>
                  <input
                    id="dataEntrega"
                    type="date"
                    value={dataEntrega}
                    onChange={(e) => setDataEntrega(e.target.value)}
                    className={`${inputClass} mt-2 w-full`}
                  />
                </div>
                <div>
                  <label htmlFor="observacoes" className={labelClass}>
                    Observa├º├Áes (m├íx. 2000 caracteres)
                  </label>
                  <textarea
                    id="observacoes"
                    value={observacoes}
                    onChange={(e) => setObservacoes(e.target.value.slice(0, 2000))}
                    maxLength={2000}
                    rows={4}
                    className={`${inputClass} mt-2 w-full`}
                    placeholder="Notas internas sobre a encomenda..."
                  />
                  <p className="mt-1 text-xs text-[#57534e] dark:text-gray-500">{observacoes.length}/2000</p>
                </div>
              </div>
            </motion.div>

            <motion.div
              initial={fadeInUp.initial}
              animate={fadeInUp.animate}
              transition={{ ...transitionSmooth, delay: 0.07 }}
              className="card-hover mt-10 rounded-2xl border border-[#e7e5e4] bg-white p-6 dark:border-[#1f1f1f] dark:bg-[#111] sm:p-8"
            >
              <h2 className="text-lg font-semibold text-gray-900 dark:text-white">Itens da encomenda</h2>
              {itens.length === 0 ? (
                <p className="mt-4 text-sm text-[#57534e] dark:text-gray-400">Nenhum item. Adicione produtos abaixo.</p>
              ) : (
                <ul className="mt-4 space-y-3">
                  {itens.map((item) => (
                    <li
                      key={item.produtoId}
                      className="flex flex-wrap items-center gap-3 rounded-xl border border-[#e7e5e4] px-4 py-3 dark:border-[#333]"
                    >
                      <span className="min-w-[180px] font-medium text-[#1c1917] dark:text-white">
                        {item.produtoNome}
                      </span>
                      <input
                        type="number"
                        min={MIN_QUANTIDADE}
                        step="any"
                        value={item.quantidade}
                        onChange={(e) => {
                          const v = parseFloat(e.target.value.replace(",", "."));
                          setQuantidade(item.produtoId, Number.isNaN(v) ? 0 : v);
                        }}
                        className={`${inputClass} w-24 text-right`}
                      />
                      <button
                        type="button"
                        onClick={() => removerItem(item.produtoId)}
                        className="text-sm text-red-600 hover:underline dark:text-red-400"
                      >
                        Remover
                      </button>
                    </li>
                  ))}
                </ul>
              )}

              <h3 className="mt-8 text-base font-semibold text-gray-900 dark:text-white">Adicionar produto</h3>
              <div className="mt-3 flex flex-wrap items-end gap-3">
                <div className="min-w-[200px] flex-1">
                  <label htmlFor="novoProduto" className={labelClass}>
                    Produto
                  </label>
                  <select
                    id="novoProduto"
                    value={novoProdutoId}
                    onChange={(e) => setNovoProdutoId(e.target.value)}
                    disabled={loadingProdutos}
                    className={`${inputClass} mt-1 w-full`}
                  >
                    <option value="">{loadingProdutos ? "A carregar produtosÔÇª" : "ÔÇö Selecionar ÔÇö"}</option>
                    {produtosSorted.map((pr) => {
                      const pid = String(pr.id ?? pr.Id);
                      return (
                        <option key={pid} value={pid} disabled={produtosJaNaEncomenda.has(pid)}>
                          {String(pr.nome ?? pr.Nome ?? "")}
                          {produtosJaNaEncomenda.has(pid) ? " (j├í na encomenda)" : ""}
                        </option>
                      );
                    })}
                  </select>
                </div>
                <div className="w-28">
                  <label htmlFor="novaQtd" className={labelClass}>
                    Quantidade
                  </label>
                  <input
                    id="novaQtd"
                    type="number"
                    min={MIN_QUANTIDADE}
                    step="any"
                    value={novaQuantidade}
                    onChange={(e) => setNovaQuantidade(e.target.value)}
                    className={`${inputClass} mt-1 w-full`}
                    placeholder="0"
                  />
                </div>
                <button type="button" onClick={adicionarItem} className={btnPrimary}>
                  Adicionar
                </button>
              </div>
            </motion.div>

            <div className="mt-8 flex flex-wrap gap-3">
              <button
                type="submit"
                className={btnPrimary}
                disabled={submitting || itens.filter((i) => i.quantidade >= MIN_QUANTIDADE).length === 0}
              >
                {submitting ? "A guardarÔÇª" : "Guardar"}
              </button>
              <Link href={`/encomendas/${id}`} className={btnSecondary}>
                Cancelar
              </Link>
            </div>
          </form>
        </div>
      </main>
    </div>
  );
}

"use client";

import { useState, useEffect, useRef } from "react";
import Link from "next/link";
import { useParams, useSearchParams, useRouter } from "next/navigation";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { motion } from "framer-motion";
import Navbar, { CONTENT_OFFSET_TOP } from "@/app/components/Navbar";
import {
  podeEditarEncomenda,
  corEstado,
  type EncomendaComClienteEItens,
  type EncomendaItem,
  type EstadoEncomenda,
} from "@/app/lib/encomendas";
import { getToken } from "@/app/lib/auth";
import { useUser } from "@/app/context/UserContext";
import { safeParseJson } from "@/app/lib/api";
import { postAceitar, postConcluir } from "@/app/lib/encomendasApi";
import type { Cliente } from "@/app/lib/clientes";
import { textoClassificacao, textoCalibre, textoGrupo, type Produto } from "@/app/lib/produtos";
import { fadeInUp, transitionSmooth } from "@/app/lib/animations";

function mapApiToEncomendaDetalhe(data: Record<string, unknown>): EncomendaComClienteEItens | null {
  const enc = data?.encomenda ?? data?.Encomenda;
  if (!enc || typeof enc !== "object") return null;
  const e = enc as Record<string, unknown>;
  const get = (key: string) => e[key] ?? e[key.charAt(0).toUpperCase() + key.slice(1)];
  const funcionarioAceiteNome = (data?.funcionarioAceiteNome ?? data?.FuncionarioAceiteNome) as string | undefined;
  const funcionarioPreparouNome = (data?.funcionarioPreparouNome ?? data?.FuncionarioPreparouNome) as string | undefined;
  const stockPorProdutoRaw = data?.stockPorProduto ?? data?.StockPorProduto;
  const stockMap = new Map<string, number>();
  if (stockPorProdutoRaw && typeof stockPorProdutoRaw === "object") {
    for (const [k, v] of Object.entries(stockPorProdutoRaw)) {
      if (typeof v === "number") stockMap.set(String(k), v);
    }
  }
  const dataCriacao = get("dataCriacao") ?? get("DataCriacao");
  const dataEntrega = get("dataEntrega") ?? get("DataEntrega");
  const dataConclusao = get("dataConclusao") ?? get("DataConclusao");
  const clienteRaw = get("cliente") ?? get("Cliente");
  const clienteObj = clienteRaw && typeof clienteRaw === "object" ? (clienteRaw as Record<string, unknown>) : null;
  const itensRaw = get("itens") ?? get("Itens");
  const itensArr = Array.isArray(itensRaw) ? itensRaw : [];
  return {
    id: String(get("id") ?? get("Id") ?? ""),
    clienteId: String(get("clienteId") ?? get("ClienteId") ?? ""),
    estado: (get("estado") ?? get("Estado") ?? "Pendente") as EstadoEncomenda,
    dataCriacao: dataCriacao ? (typeof dataCriacao === "string" ? dataCriacao : new Date(dataCriacao as string).toISOString()) : new Date().toISOString(),
    dataEntrega: dataEntrega ? (typeof dataEntrega === "string" ? dataEntrega : new Date(dataEntrega as string).toISOString().slice(0, 10)) : undefined,
    observacoes: (get("observacoes") ?? get("Observacoes")) as string | undefined,
    motivoRejeicao: (get("motivoRejeicao") ?? get("MotivoRejeicao")) as string | undefined,
    funcionarioAceiteUserId: (get("funcionarioAceiteUserId") ?? get("FuncionarioAceiteUserId")) as string | undefined,
    funcionarioAceiteNome,
    funcionarioPreparouUserId: (get("funcionarioPreparouUserId") ?? get("FuncionarioPreparouUserId")) as string | undefined,
    funcionarioPreparouNome,
    dataConclusao: dataConclusao ? (typeof dataConclusao === "string" ? dataConclusao : new Date(dataConclusao as string).toISOString()) : undefined,
    cliente: clienteObj
      ? ({
          id: String(clienteObj.id ?? clienteObj.Id ?? ""),
          nome: String(clienteObj.nome ?? clienteObj.Nome ?? ""),
          tipoCliente: "Empresa" as const,
          dataRegisto: new Date().toISOString(),
          documentosExtras: [],
        } as Cliente)
      : null,
    itens: itensArr.map((i: Record<string, unknown>) => {
      const gi = (k: string) => i[k] ?? i[k.charAt(0).toUpperCase() + k.slice(1)];
      const prod = gi("produto") ?? gi("Produto");
      const prodObj = prod && typeof prod === "object" ? (prod as Record<string, unknown>) : null;
      return {
        id: String(gi("id") ?? gi("Id") ?? ""),
        encomendaId: String(gi("encomendaId") ?? gi("EncomendaId") ?? ""),
        produtoId: String(gi("produtoId") ?? gi("ProdutoId") ?? ""),
        quantidadePedida: Number(gi("quantidadePedida") ?? gi("QuantidadePedida") ?? 0),
        produto: prodObj ? { id: String(prodObj.id ?? prodObj.Id ?? ""), nome: String(prodObj.nome ?? prodObj.Nome ?? "") } as Produto : null,
        produtoNome: prodObj ? String(prodObj.nome ?? prodObj.Nome ?? "") : undefined,
      };
    }) as (EncomendaItem & { produto?: Produto | null; produtoNome?: string })[],
    stockPorProduto: stockMap,
  };
}

import { apiPath } from "@/app/lib/apiConfig";

const btnPrimary =
  "data-button rounded-xl bg-[#f97316] px-4 py-2 text-sm font-semibold text-black transition-[opacity,background-color] duration-200 hover:opacity-90 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[#f97316]";

const btnSecondary =
  "data-button rounded-xl border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 dark:border-[#333] dark:text-gray-300 dark:hover:bg-[#1a1a1a]";

const btnDanger =
  "data-button rounded-xl border border-red-300 px-4 py-2 text-sm font-medium text-red-700 hover:bg-red-50 dark:border-red-800 dark:text-red-400 dark:hover:bg-red-950";

const labelClass = "block text-sm font-medium text-gray-700 dark:text-gray-300";
const valueClass = "mt-1 text-gray-900 dark:text-white";

export default function EncomendaDetalhePage() {
  const params = useParams();
  const searchParams = useSearchParams();
  const router = useRouter();
  const id = params.id as string;
  const queryClient = useQueryClient();
  const { user } = useUser();
  const userId = user?.id ?? user?.email ?? "";
  const canGerirEncomendas = (user?.permissions ?? []).includes("encomendas.gerir");
  const canGerirServicos = (user?.permissions ?? []).includes("servicos.gerir");
  const [erroAcao, setErroAcao] = useState<string | null>(null);
  const aceitarRef = useRef(false);
  const concluirRef = useRef(false);

  const criada = searchParams.get("criada") === "1";
  const editada = searchParams.get("editada") === "1";
  const itensEditados = searchParams.get("itensEditados") === "1";
  const aceite = searchParams.get("aceite") === "1";
  const rejeitada = searchParams.get("rejeitada") === "1";
  const preparacao = searchParams.get("preparacao") === "1";
  const concluida = searchParams.get("concluida") === "1";
  const erro = searchParams.get("erro") === "1";
  const voltarHref = searchParams.get("voltar") ?? "/encomendas";
  const voltarLabel = voltarHref.includes("movimentos") ? "Voltar aos movimentos" : "Voltar ├á lista";

  const numId = parseInt(id, 10);
  const validId = !Number.isNaN(numId);

  const {
    data: encomenda,
    isLoading: loadingApi,
    isRefetching,
    error: queryError,
  } = useQuery({
    queryKey: ["encomendas", id],
    queryFn: async (): Promise<EncomendaComClienteEItens | null> => {
      const token = getToken();
      if (!token) {
        router.replace("/login");
        throw new Error("Sess├úo expirada.");
      }
      const res = await fetch(`${apiPath("api/encomendas")}/${numId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      if (res.status === 401) {
        router.replace("/login");
        throw new Error("Sess├úo expirada.");
      }
      if (res.status === 404) return null;
      if (!res.ok) throw new Error(`Erro ${res.status}`);
      const data = (await safeParseJson(res)) as Record<string, unknown>;
      return mapApiToEncomendaDetalhe(data);
    },
    staleTime: 30 * 1000,
    retry: 2,
    enabled: validId && !!getToken(),
  });

  if (loadingApi) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-[#fafafa] dark:bg-[#0a0a0a]">
        <div className="h-8 w-8 animate-spin rounded-full border-2 border-[#f97316] border-t-transparent" />
      </div>
    );
  }

  if (queryError || !encomenda) {
    return (
      <div className="min-h-screen bg-[#f8f7f5] dark:bg-[#0a0a0a]">
        <Navbar />
        <main style={{ paddingTop: CONTENT_OFFSET_TOP }} className="p-8">
          {queryError && (
            <p className="rounded-xl bg-red-100 px-4 py-3 text-sm text-red-800 dark:bg-red-900/30 dark:text-red-400">
              {queryError instanceof Error ? queryError.message : "Erro ao carregar encomenda."}
            </p>
          )}
          {!queryError && <p className="text-gray-600 dark:text-gray-400">Encomenda n├úo encontrada.</p>}
          <Link href={voltarHref} className="mt-4 inline-block text-[#f97316] hover:underline">
            ÔåÉ {voltarLabel}
          </Link>
        </main>
      </div>
    );
  }

  const idNum = parseInt(id, 10);
  const isApiId = !Number.isNaN(idNum);

  const handleAceitar = async (e: React.FormEvent) => {
    e.preventDefault();
    if (aceitarRef.current) return;
    setErroAcao(null);
    const token = getToken();
    if (!token || !isApiId) {
      setErroAcao("Sess├úo expirada ou identificador inv├ílido.");
      return;
    }
    aceitarRef.current = true;
    try {
      await postAceitar(token, idNum);
      queryClient.invalidateQueries({ queryKey: ["encomendas", id] });
      router.push(`/encomendas/${id}?aceite=1`);
    } catch (err) {
      const msg = err instanceof Error ? err.message : "Ocorreu um erro. Tente novamente.";
      setErroAcao(msg === "Failed to fetch"
        ? "N├úo foi poss├¡vel contactar a API. Confirme que o backend est├í a correr (ver vari├ível NEXT_PUBLIC_API_URL)."
        : msg);
    } finally {
      aceitarRef.current = false;
    }
  };

  const handleConcluir = async (e: React.FormEvent) => {
    e.preventDefault();
    if (concluirRef.current) return;
    setErroAcao(null);
    const token = getToken();
    if (!token || !isApiId) {
      setErroAcao("Sess├úo expirada ou identificador inv├ílido.");
      return;
    }
    concluirRef.current = true;
    try {
      await postConcluir(token, idNum);
      queryClient.invalidateQueries({ queryKey: ["encomendas", id] });
      router.push(`/encomendas/${id}?concluida=1`);
    } catch (err) {
      const msg = err instanceof Error ? err.message : "Ocorreu um erro. Tente novamente.";
      setErroAcao(msg === "Failed to fetch"
        ? "N├úo foi poss├¡vel contactar a API. Confirme que o backend est├í a correr (ver vari├ível NEXT_PUBLIC_API_URL)."
        : msg);
    } finally {
      concluirRef.current = false;
    }
  };

  const { cliente, itens, stockPorProduto, estado } = encomenda;
  const algumSemStock = itens.some((i) => (stockPorProduto.get(i.produtoId) ?? 0) < i.quantidadePedida);
  const currentUserId = userId && userId !== "current-user" ? userId : null;
  const podeEditar = podeEditarEncomenda(encomenda, currentUserId, canGerirEncomendas);

  return (
    <div className="min-h-screen bg-[#f8f7f5] text-[#1c1917] dark:bg-[#0a0a0a] dark:text-white">
      <Navbar />

      <main
        className="relative px-6 pt-14 pb-10 sm:px-8"
        style={{ paddingTop: CONTENT_OFFSET_TOP }}
      >
        <div className="mx-auto max-w-5xl">
          {(criada || editada || itensEditados || aceite || rejeitada || preparacao || concluida) && (
            <motion.p
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={transitionSmooth}
              className="mb-6 rounded-xl bg-green-100 px-4 py-3 text-sm text-green-800 dark:bg-green-900/30 dark:text-green-400"
            >
              {criada && "Encomenda criada com sucesso."}
              {editada && "Altera├º├Áes guardadas."}
              {itensEditados && "Itens da encomenda atualizados."}
              {aceite && "Encomenda aceite."}
              {rejeitada && "Encomenda rejeitada. As reservas foram libertadas."}
              {preparacao && "Prepara├º├úo registada."}
              {concluida && "Encomenda marcada como conclu├¡da."}
            </motion.p>
          )}
          {(erro || erroAcao) && (
            <motion.p
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={transitionSmooth}
              className="mb-6 rounded-xl bg-red-100 px-4 py-3 text-sm text-red-800 dark:bg-red-900/30 dark:text-red-400"
            >
              {erroAcao ?? "Ocorreu um erro. Tente novamente."}
            </motion.p>
          )}

          <motion.div
            initial={fadeInUp.initial}
            animate={fadeInUp.animate}
            transition={transitionSmooth}
            className="flex flex-col gap-4 sm:flex-row sm:items-start sm:justify-between"
          >
            <div>
              <h1 className="font-heading text-2xl tracking-tight sm:text-3xl">
                Encomenda #{encomenda.id}
              </h1>
              <p className="mt-1 flex flex-wrap items-center gap-2 text-[#57534e] dark:text-gray-400">
                Cliente:{" "}
                {cliente ? (
                  <Link href={`/clientes/${encomenda.clienteId}`} className="text-[#f97316] hover:underline">
                    {cliente.nome}
                  </Link>
                ) : (
                  encomenda.clienteId
                )}
                {isRefetching && (
                  <span className="inline-flex items-center gap-1.5 text-xs text-[#78716c] dark:text-gray-500">
                    <span className="h-1.5 w-1.5 shrink-0 animate-pulse rounded-full bg-[#f97316]" />
                    A atualizar
                  </span>
                )}
              </p>
            </div>
            <span className={`inline-block rounded-full px-3 py-1 text-sm font-medium ${corEstado(estado)}`}>
              {estado}
            </span>
          </motion.div>

          {canGerirEncomendas && estado === "Pendente" && (
            <motion.div
              initial={fadeInUp.initial}
              animate={fadeInUp.animate}
              transition={{ ...transitionSmooth, delay: 0.03 }}
              className="mt-6 rounded-xl border border-amber-200 bg-amber-50 px-4 py-3 dark:border-amber-800 dark:bg-amber-900/20"
            >
              <p className="text-sm text-amber-800 dark:text-amber-200">
                Consulte a coluna &quot;Em stock&quot; antes de aceitar ou rejeitar a encomenda.
              </p>
            </motion.div>
          )}

          <motion.div
            initial={fadeInUp.initial}
            animate={fadeInUp.animate}
            transition={{ ...transitionSmooth, delay: 0.05 }}
            className="card-hover mt-10 rounded-2xl border border-[#e7e5e4] bg-white p-6 dark:border-[#1f1f1f] dark:bg-[#111] sm:p-8"
          >
            <h2 className="text-lg font-semibold text-gray-900 dark:text-white">
              Cliente e datas
            </h2>
            <dl className="mt-4 grid gap-4 sm:grid-cols-2">
              <div>
                <dt className={labelClass}>Cliente</dt>
                <dd className={valueClass}>
                  {cliente ? (
                    <Link href={`/clientes/${encomenda.clienteId}`} className="text-[#f97316] hover:underline">
                      {cliente.nome}
                    </Link>
                  ) : (
                    encomenda.clienteId
                  )}
                </dd>
              </div>
              <div>
                <dt className={labelClass}>Estado</dt>
                <dd className={valueClass}>{encomenda.estado}</dd>
              </div>
              <div>
                <dt className={labelClass}>Data de cria├º├úo</dt>
                <dd className={valueClass}>{new Date(encomenda.dataCriacao).toLocaleString("pt-PT")}</dd>
              </div>
              <div>
                <dt className={labelClass}>Data de entrega</dt>
                <dd className={valueClass}>{encomenda.dataEntrega ? new Date(encomenda.dataEntrega).toLocaleDateString("pt-PT") : "ÔÇö"}</dd>
              </div>
              <div>
                <dt className={labelClass}>Aceite por</dt>
                <dd className={valueClass}>{encomenda.funcionarioAceiteNome ?? encomenda.funcionarioAceiteUserId ?? "ÔÇö"}</dd>
              </div>
              <div>
                <dt className={labelClass}>Preparado por</dt>
                <dd className={valueClass}>{encomenda.funcionarioPreparouNome ?? encomenda.funcionarioPreparouUserId ?? "ÔÇö"}</dd>
              </div>
              <div>
                <dt className={labelClass}>Data de conclus├úo</dt>
                <dd className={valueClass}>{encomenda.dataConclusao ? new Date(encomenda.dataConclusao).toLocaleString("pt-PT") : "ÔÇö"}</dd>
              </div>
              {(encomenda.observacoes || encomenda.motivoRejeicao) && (
                <>
                  {encomenda.observacoes && (
                    <div className="sm:col-span-2">
                      <dt className={labelClass}>Observa├º├Áes</dt>
                      <dd className={valueClass}>{encomenda.observacoes}</dd>
                    </div>
                  )}
                  {encomenda.motivoRejeicao && (
                    <div className="sm:col-span-2">
                      <dt className={labelClass}>Motivo de rejei├º├úo</dt>
                      <dd className={valueClass}>{encomenda.motivoRejeicao}</dd>
                    </div>
                  )}
                </>
              )}
            </dl>
          </motion.div>

          <motion.div
            initial={fadeInUp.initial}
            animate={fadeInUp.animate}
            transition={{ ...transitionSmooth, delay: 0.07 }}
            className="card-hover mt-10 rounded-2xl border border-[#e7e5e4] bg-white p-6 dark:border-[#1f1f1f] dark:bg-[#111] sm:p-8"
          >
            <h2 className="text-lg font-semibold text-gray-900 dark:text-white">
              Itens da encomenda
            </h2>
            <div className="mt-4 overflow-x-auto">
              <table className="w-full text-left text-sm">
                <thead>
                  <tr className="border-b border-[#e7e5e4] dark:border-[#222]">
                    <th className="pb-2 pr-4 font-semibold text-[#444] dark:text-gray-300">Produto</th>
                    <th className="whitespace-nowrap pb-2 pr-4 font-semibold text-[#444] dark:text-gray-300">Calibre</th>
                    <th className="whitespace-nowrap pb-2 pr-4 font-semibold text-[#444] dark:text-gray-300">Grupo risco</th>
                    <th className="whitespace-nowrap pb-2 pr-4 font-semibold text-[#444] dark:text-gray-300">Qtd pedida</th>
                    <th className="whitespace-nowrap pb-2 pr-4 font-semibold text-[#444] dark:text-gray-300">Em stock</th>
                  </tr>
                </thead>
                <tbody>
                  {itens.map((item) => {
                    const stock = stockPorProduto.get(item.produtoId) ?? 0;
                    const suficiente = stock >= item.quantidadePedida;
                    return (
                      <tr key={item.id} className="border-b border-[#f5f5f4] dark:border-[#1a1a1a]">
                        <td className="py-2 pr-4 font-medium text-[#1c1917] dark:text-white">{item.produto?.nome ?? item.produtoId}</td>
                        <td className="whitespace-nowrap py-2 pr-4 text-[#57534e] dark:text-gray-400">{textoCalibre(item.produto?.calibre)}</td>
                        <td className="whitespace-nowrap py-2 pr-4 text-[#57534e] dark:text-gray-400">{textoGrupo(item.produto?.grupoCompatibilidade)}</td>
                        <td className="whitespace-nowrap py-2 pr-4 text-[#57534e] dark:text-gray-400">{item.quantidadePedida}</td>
                        <td className={`whitespace-nowrap py-2 pr-4 ${suficiente ? "text-green-700 dark:text-green-400" : "text-red-700 dark:text-red-400"}`}>
                          {stock}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </motion.div>

          {estado === "Conclu├¡da" && (
            <motion.section
              initial={fadeInUp.initial}
              animate={fadeInUp.animate}
              transition={{ ...transitionSmooth, delay: 0.09 }}
              className="card-hover mt-10 rounded-2xl border border-[#e7e5e4] bg-white p-6 dark:border-[#1f1f1f] dark:bg-[#111] sm:p-8"
            >
              <h2 className="text-lg font-semibold text-gray-900 dark:text-white">
                Servi├ºos no terreno
              </h2>
              <p className="mt-2 text-sm text-[#57534e] dark:text-gray-400">
                Com a encomenda conclu├¡da, pode registar um servi├ºo (evento no terreno) associado a este pedido. O formul├írio abre j├í com esta encomenda selecionada.
              </p>
              <div className="mt-4 flex flex-wrap items-center gap-3">
                {canGerirServicos ? (
                  <Link
                    href={`/servicos/novo?encomendaId=${encodeURIComponent(id)}`}
                    className={btnPrimary}
                  >
                    Realizar servi├ºo com esta encomenda
                  </Link>
                ) : (
                  <p className="text-sm text-[#78716c] dark:text-gray-500">
                    Para criar servi├ºos ├® necess├íria a permiss├úo de gest├úo de servi├ºos.
                  </p>
                )}
                <Link href="/servicos" className={`${btnSecondary} inline-block text-center`}>
                  Lista de servi├ºos
                </Link>
              </div>
            </motion.section>
          )}

          <div className="mt-10 flex flex-wrap gap-3">
            {estado === "Pendente" && (
              <>
                {canGerirEncomendas && (
                  <form onSubmit={handleAceitar} className="inline-block">
                    <button type="submit" className={btnPrimary}>
                      Aceitar encomenda
                    </button>
                  </form>
                )}
                {podeEditar && (
                  <Link href={`/encomendas/${id}/editar`} className={btnSecondary}>
                    Editar
                  </Link>
                )}
                {canGerirEncomendas && (
                  <Link href={`/encomendas/${id}/rejeitar`} className={btnDanger}>
                    Rejeitar
                  </Link>
                )}
              </>
            )}
            {estado === "Aceite" && (
              <>
                {canGerirEncomendas && (
                  <>
                    <Link href={`/encomendas/${id}/preparar`} className={btnPrimary}>
                      Iniciar prepara├º├úo
                    </Link>
                    <Link href={`/encomendas/${id}/rejeitar`} className={btnDanger}>
                      Rejeitar
                    </Link>
                  </>
                )}
                {podeEditar && (
                  <Link href={`/encomendas/${id}/editar`} className={btnSecondary}>
                    Editar
                  </Link>
                )}
              </>
            )}
            {((estado as string) === "Em prepara├º├úo" || (estado as string) === "Em preparacao") && canGerirEncomendas && (
              <form onSubmit={handleConcluir} className="inline-block">
                <button type="submit" className={btnPrimary}>
                  Concluir encomenda
                </button>
              </form>
            )}
            <Link href={voltarHref} className={btnSecondary}>
              {voltarLabel}
            </Link>
          </div>
        </div>
      </main>
    </div>
  );
}

"use client";

import React, { useState, useEffect, useMemo, useRef } from "react";
import Link from "next/link";
import { useParams, useRouter } from "next/navigation";
import { motion } from "framer-motion";
import Navbar, { CONTENT_OFFSET_TOP } from "@/app/components/Navbar";
import { getToken } from "@/app/lib/auth";
import { fetchPreparar, postRegistarPreparacao, type RetiradaPreparacaoInput } from "@/app/lib/encomendasApi";
import { fadeInUp, transitionSmooth } from "@/app/lib/animations";

const inputClass =
  "w-20 rounded-lg border border-gray-300 bg-white px-2 py-1.5 text-right text-sm text-gray-900 dark:border-[#333] dark:bg-[#1a1a1a] dark:text-white";

const btnPrimary =
  "data-button rounded-xl bg-[#f97316] px-4 py-2 text-sm font-semibold text-black transition-[opacity,background-color] duration-200 hover:opacity-90 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[#f97316]";

const btnDanger =
  "data-button rounded-xl border border-red-300 px-4 py-2 text-sm font-medium text-red-700 hover:bg-red-50 dark:border-red-800 dark:text-red-400 dark:hover:bg-red-950";

const btnSecondary =
  "data-button rounded-xl border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 dark:border-[#333] dark:text-gray-300 dark:hover:bg-[#1a1a1a]";

const TOL = 0.0001;

type ItemPreparar = { id: string; produtoId: string; quantidadePedida: number; produto?: { nome?: string } | null; produtoNome?: string };
type PaiolPreparar = { id: string; nome: string };

export default function PrepararEncomendaPage() {
  const params = useParams();
  const router = useRouter();
  const id = params.id as string;
  const [mounted, setMounted] = useState(false);
  const [retiradas, setRetiradas] = useState<Record<string, Record<string, number>>>({});
  const [expandedItemId, setExpandedItemId] = useState<string | null>(null);
  const [erro, setErro] = useState<string | null>(null);
  const [submitting, setSubmitting] = useState(false);
  const submittingRef = useRef(false);
  const [apiData, setApiData] = useState<{
    encomenda: { itens: ItemPreparar[]; cliente?: { nome?: string }; clienteId?: string };
    paiois: PaiolPreparar[];
    stockPorProduto: Record<string, number>;
    stockPaiolProduto: Record<string, number>;
  } | null>(null);
  const [loadingApi, setLoadingApi] = useState(true);

  const idNum = parseInt(id, 10);
  const isApiId = !Number.isNaN(idNum);

  const stockPaiolProduto = useMemo(() => {
    const m = new Map<string, number>();
    if (apiData?.stockPaiolProduto) {
      for (const [k, v] of Object.entries(apiData.stockPaiolProduto)) m.set(k, Number(v));
    }
    return m;
  }, [apiData?.stockPaiolProduto]);
  const stockPorProdutoMap = useMemo(() => {
    const m = new Map<string, number>();
    if (apiData?.stockPorProduto) {
      for (const [k, v] of Object.entries(apiData.stockPorProduto)) m.set(k, Number(v));
    }
    return m;
  }, [apiData?.stockPorProduto]);
  const encomenda = useMemo(() => {
    const base = apiData?.encomenda;
    if (!base) return null;
    return { ...base, stockPorProduto: stockPorProdutoMap };
  }, [apiData?.encomenda, stockPorProdutoMap]);
  const paiois = apiData?.paiois ?? [];

  useEffect(() => {
    setMounted(true);
  }, [id]);

  useEffect(() => {
    if (!mounted || !isApiId) {
      setApiData(null);
      setLoadingApi(false);
      return;
    }
    const token = getToken();
    if (!token) {
      setApiData(null);
      setLoadingApi(false);
      return;
    }
    fetchPreparar(token, idNum)
      .then((data) => {
        const enc = data.encomenda as Record<string, unknown>;
        const itensRaw = enc?.itens ?? enc?.Itens ?? [];
        const itens: ItemPreparar[] = Array.isArray(itensRaw)
          ? itensRaw.map((i: Record<string, unknown>) => {
              const gi = (k: string) => i[k] ?? i[k.charAt(0).toUpperCase() + k.slice(1)];
              const prod = gi("produto") ?? gi("Produto");
              const prodObj = prod && typeof prod === "object" ? (prod as Record<string, unknown>) : null;
              return {
                id: String(gi("id") ?? gi("Id") ?? ""),
                produtoId: String(gi("produtoId") ?? gi("ProdutoId") ?? ""),
                quantidadePedida: Number(gi("quantidadePedida") ?? gi("QuantidadePedida") ?? 0),
                produto: prodObj ? { nome: String(prodObj.nome ?? prodObj.Nome ?? "") } : null,
                produtoNome: prodObj ? String(prodObj.nome ?? prodObj.Nome ?? "") : undefined,
              };
            })
          : [];
        const dataAny = data as unknown as Record<string, unknown>;
        const paioisRaw = (dataAny["pai├│is"] ?? dataAny["paiois"] ?? []) as unknown;
        const paioisMapped: PaiolPreparar[] = Array.isArray(paioisRaw)
          ? paioisRaw.map((p: { id?: number; nome?: string }) => ({ id: String(p.id ?? ""), nome: String(p.nome ?? "") }))
          : [];
        setApiData({
          encomenda: {
            itens: itens,
            cliente: (enc?.cliente ?? enc?.Cliente) as { nome?: string },
            clienteId: String(enc?.clienteId ?? enc?.ClienteId ?? ""),
          },
          paiois: paioisMapped,
          stockPorProduto: (data.stockPorProduto ?? {}) as Record<string, number>,
          stockPaiolProduto: (data.stockPaiolProduto ?? {}) as Record<string, number>,
        });
      })
      .catch(() => setApiData(null))
      .finally(() => setLoadingApi(false));
  }, [mounted, id, idNum, isApiId]);

  const setRetirada = (encomendaItemId: string, paiolId: string, value: number) => {
    setRetiradas((prev) => {
      const next = { ...prev };
      if (!next[encomendaItemId]) next[encomendaItemId] = {};
      next[encomendaItemId] = { ...next[encomendaItemId], [paiolId]: value };
      return next;
    });
  };

  const getRetirada = (encomendaItemId: string, paiolId: string): number =>
    retiradas[encomendaItemId]?.[paiolId] ?? 0;

  /** Pai├│is que t├¬m stock deste produto (para mostrar s├│ os relevantes na linha expandida) */
  const paioisComStockPorItem = useMemo(() => {
    const map = new Map<string, PaiolPreparar[]>();
    if (!encomenda) return map;
    for (const item of encomenda.itens) {
      const lista = paiois.filter((p) => (stockPaiolProduto.get(`${p.id}_${item.produtoId}`) ?? 0) > 0);
      map.set(item.id, lista);
    }
    return map;
  }, [encomenda, paiois, stockPaiolProduto]);

  /** Texto resumo "P1: 5, P2: 3" para a coluna Retirar de */
  const resumoRetiradas = (itemId: string): string => {
    const itemRet = retiradas[itemId];
    if (!itemRet) return "ÔÇö";
    const partes = Object.entries(itemRet)
      .filter(([, q]) => q > 0)
      .map(([paiolId]) => {
        const p = paiois.find((x) => x.id === paiolId);
        return p ? `${p.nome}: ${Number(itemRet[paiolId]).toFixed(4)}` : "";
      })
      .filter(Boolean);
    return partes.length > 0 ? partes.join(", ") : "ÔÇö";
  };

  const somaPorItem = useMemo(() => {
    const map = new Map<string, number>();
    if (!encomenda) return map;
    for (const item of encomenda.itens) {
      let s = 0;
      const itemRet = retiradas[item.id];
      if (itemRet) for (const q of Object.values(itemRet)) s += q;
      map.set(item.id, s);
    }
    return map;
  }, [encomenda, retiradas]);

  const validacaoOk = useMemo(() => {
    if (!encomenda) return false;
    return encomenda.itens.every(
      (item) => Math.abs((somaPorItem.get(item.id) ?? 0) - item.quantidadePedida) <= TOL
    );
  }, [encomenda, somaPorItem]);

  const algumSemStockTotal = encomenda?.itens.some(
    (item) => (encomenda.stockPorProduto.get(item.produtoId) ?? 0) < item.quantidadePedida
  );

  if (!mounted) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-[#fafafa] dark:bg-[#0a0a0a]">
        <div className="h-8 w-8 animate-spin rounded-full border-2 border-[#f97316] border-t-transparent" />
      </div>
    );
  }

  if (loadingApi && isApiId && getToken()) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-[#fafafa] dark:bg-[#0a0a0a]">
        <div className="h-8 w-8 animate-spin rounded-full border-2 border-[#f97316] border-t-transparent" />
      </div>
    );
  }

  if (!encomenda) {
    return (
      <div className="min-h-screen bg-[#f8f7f5] dark:bg-[#0a0a0a]">
        <Navbar />
        <main style={{ paddingTop: CONTENT_OFFSET_TOP }} className="p-8">
          <p className="text-gray-600 dark:text-gray-400">
            Encomenda n├úo encontrada ou estado n├úo permite prepara├º├úo (tem de estar Aceite).
          </p>
          <Link href="/encomendas" className="mt-4 inline-block text-[#f97316] hover:underline">
            ÔåÉ Voltar ├ás Encomendas
          </Link>
        </main>
      </div>
    );
  }

  const handleRegistar = async (e: React.FormEvent) => {
    e.preventDefault();
    if (submittingRef.current) return;
    setErro(null);
    if (!validacaoOk) {
      setErro("A soma das quantidades por produto deve ser igual ├á quantidade pedida.");
      return;
    }
    const token = getToken();
    if (!isApiId || !token) {
      setErro("Sess├úo inv├ílida. Fa├ºa login.");
      return;
    }
    const listaApi: RetiradaPreparacaoInput[] = [];
    for (const item of encomenda.itens) {
      for (const p of paiois) {
        const q = getRetirada(item.id, p.id);
        if (q > 0) {
          listaApi.push({
            encomendaItemId: parseInt(item.id, 10),
            paiolId: parseInt(p.id, 10),
            quantidade: q,
          });
        }
      }
    }
    submittingRef.current = true;
    setSubmitting(true);
    try {
      await postRegistarPreparacao(token, idNum, listaApi);
      router.push(`/encomendas/${id}?preparacao=1`);
    } catch (err) {
      setErro(err instanceof Error ? err.message : "Erro ao registar prepara├º├úo.");
    } finally {
      submittingRef.current = false;
      setSubmitting(false);
    }
  };

  const clienteNome = encomenda.cliente?.nome ?? encomenda.clienteId;

  return (
    <div className="min-h-screen bg-[#f8f7f5] text-[#1c1917] dark:bg-[#0a0a0a] dark:text-white">
      <Navbar />

      <main
        className="relative px-6 pt-14 pb-10 sm:px-8"
        style={{ paddingTop: CONTENT_OFFSET_TOP }}
      >
        <div className="mx-auto max-w-5xl">
          <motion.div
            initial={fadeInUp.initial}
            animate={fadeInUp.animate}
            transition={transitionSmooth}
          >
            <h1 className="font-heading text-2xl tracking-tight sm:text-3xl">
              Registar prepara├º├úo
            </h1>
            <p className="mt-1 text-[#57534e] dark:text-gray-400">
              Encomenda #{id} ┬À Cliente: {clienteNome}
            </p>
          </motion.div>

          {algumSemStockTotal && (
            <motion.div
              initial={fadeInUp.initial}
              animate={fadeInUp.animate}
              transition={{ ...transitionSmooth, delay: 0.03 }}
              className="mt-6 rounded-xl border border-amber-200 bg-amber-50 px-4 py-3 dark:border-amber-800 dark:bg-amber-900/20"
            >
              <p className="text-sm text-amber-800 dark:text-amber-200">
                Algum item tem stock total insuficiente. Ajuste as quantidades por paiol ou rejeite a encomenda.
              </p>
            </motion.div>
          )}

          {erro && (
            <p className="mt-6 rounded-xl bg-red-100 px-4 py-3 text-sm text-red-800 dark:bg-red-900/30 dark:text-red-400">
              {erro}
            </p>
          )}

          <motion.div
            initial={fadeInUp.initial}
            animate={fadeInUp.animate}
            transition={{ ...transitionSmooth, delay: 0.05 }}
            className="card-hover mt-10 rounded-2xl border border-[#e7e5e4] bg-white p-6 dark:border-[#1f1f1f] dark:bg-[#111] sm:p-8"
          >
            <p className="mb-4 text-sm text-[#57534e] dark:text-gray-400">
              Para cada produto, indique de que paiol(s) retirar. A soma por produto deve ser igual ├á quantidade pedida. O sistema usa FIFO (primeiro a entrar, primeiro a sair).
            </p>

            <form onSubmit={handleRegistar}>
              <div className="overflow-x-auto">
                <table className="w-full text-left text-sm">
                  <thead>
                    <tr className="border-b border-[#e7e5e4] dark:border-[#222]">
                      <th className="pb-2 pr-4 font-semibold text-[#444] dark:text-gray-300">Produto</th>
                      <th className="whitespace-nowrap pb-2 pr-4 font-semibold text-[#444] dark:text-gray-300">Qtd pedida</th>
                      <th className="whitespace-nowrap pb-2 pr-4 font-semibold text-[#444] dark:text-gray-300">Em stock</th>
                      <th className="pb-2 pr-4 font-semibold text-[#444] dark:text-gray-300">Retirar de</th>
                      <th className="whitespace-nowrap pb-2 pr-4 font-semibold text-[#444] dark:text-gray-300">Soma</th>
                    </tr>
                  </thead>
                  <tbody>
                    {encomenda.itens.map((item) => {
                      const stockTotal = encomenda.stockPorProduto.get(item.produtoId) ?? 0;
                      const soma = somaPorItem.get(item.id) ?? 0;
                      const ok = Math.abs(soma - item.quantidadePedida) <= TOL;
                      const paioisComStock = paioisComStockPorItem.get(item.id) ?? [];
                      const isExpanded = expandedItemId === item.id;
                      return (
                        <React.Fragment key={item.id}>
                          <tr className="border-b border-[#f5f5f4] dark:border-[#1a1a1a]">
                            <td className="py-2 pr-4 font-medium text-[#1c1917] dark:text-white">
                              {item.produto?.nome ?? item.produtoId}
                            </td>
                            <td className="whitespace-nowrap py-2 pr-4 text-[#57534e] dark:text-gray-400">
                              {item.quantidadePedida}
                            </td>
                            <td className="whitespace-nowrap py-2 pr-4 text-[#57534e] dark:text-gray-400">
                              {stockTotal}
                            </td>
                            <td className="py-2 pr-4">
                              <span className="text-[#57534e] dark:text-gray-400">{resumoRetiradas(item.id)}</span>
                              {paioisComStock.length > 0 && (
                                <button
                                  type="button"
                                  onClick={() => setExpandedItemId(isExpanded ? null : item.id)}
                                  className="ml-2 rounded-lg border border-[#e7e5e4] bg-white px-2 py-1 text-xs font-medium text-[#57534e] hover:bg-[#fafaf9] dark:border-[#333] dark:bg-[#1a1a1a] dark:text-gray-400 dark:hover:bg-[#222]"
                                >
                                  {isExpanded ? "Fechar" : "Definir"}
                                </button>
                              )}
                            </td>
                            <td className={`whitespace-nowrap py-2 pr-4 font-medium ${ok ? "text-green-700 dark:text-green-400" : "text-red-700 dark:text-red-400"}`}>
                              {soma.toFixed(4)}
                            </td>
                          </tr>
                          {isExpanded && paioisComStock.length > 0 && (
                            <tr className="border-b border-[#f5f5f4] bg-[#fafaf9] dark:border-[#1a1a1a] dark:bg-[#0d0d0d]">
                              <td colSpan={5} className="px-4 py-3">
                                <p className="mb-2 text-xs font-medium uppercase tracking-wider text-[#78716c] dark:text-gray-500">
                                  Quantidade a retirar de cada paiol (soma = {item.quantidadePedida})
                                </p>
                                <div className="flex flex-wrap gap-4">
                                  {paioisComStock.map((p) => {
                                    const key = `${p.id}_${item.produtoId}`;
                                    const stockAqui = stockPaiolProduto.get(key) ?? 0;
                                    return (
                                      <div key={p.id} className="flex items-center gap-2">
                                        <label htmlFor={`ret-${item.id}-${p.id}`} className="min-w-[100px] text-sm text-[#57534e] dark:text-gray-400">
                                          {p.nome} <span className="text-[#78716c]">(m├íx. {stockAqui})</span>
                                        </label>
                                        <input
                                          id={`ret-${item.id}-${p.id}`}
                                          type="number"
                                          min={0}
                                          max={stockAqui}
                                          step="any"
                                          value={getRetirada(item.id, p.id) || ""}
                                          onChange={(e) => {
                                            const v = parseFloat(e.target.value.replace(",", "."));
                                            setRetirada(item.id, p.id, Number.isNaN(v) ? 0 : v);
                                          }}
                                          className={inputClass}
                                          placeholder="0"
                                        />
                                      </div>
                                    );
                                  })}
                                </div>
                              </td>
                            </tr>
                          )}
                        </React.Fragment>
                      );
                    })}
                  </tbody>
                </table>
              </div>

              <div className="mt-8 flex flex-wrap gap-3">
                <button type="submit" className={btnPrimary} disabled={submitting || !validacaoOk}>
                  {submitting ? "A registarÔÇª" : "Registar prepara├º├úo"}
                </button>
                <Link href={`/encomendas/${id}/rejeitar`} className={btnDanger}>
                  Rejeitar encomenda
                </Link>
                <Link href={`/encomendas/${id}`} className={btnSecondary}>
                  Cancelar
                </Link>
              </div>
            </form>
          </motion.div>
        </div>
      </main>
    </div>
  );
}

"use client";

import { useState, useEffect, useRef } from "react";
import Link from "next/link";
import { useParams, useRouter } from "next/navigation";
import { motion } from "framer-motion";
import Navbar, { CONTENT_OFFSET_TOP } from "@/app/components/Navbar";
import { getToken } from "@/app/lib/auth";
import { fetchRejeitar, postRejeitar } from "@/app/lib/encomendasApi";
import { fadeInUp, transitionSmooth } from "@/app/lib/animations";

const inputClass =
  "rounded-xl border border-gray-300 bg-white px-3 py-2 text-gray-900 dark:border-[#333] dark:bg-[#1a1a1a] dark:text-white";

const labelClass = "block text-sm font-medium text-gray-700 dark:text-gray-300";

const btnPrimary =
  "data-button rounded-xl bg-[#f97316] px-4 py-2 text-sm font-semibold text-black transition-[opacity,background-color] duration-200 hover:opacity-90 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[#f97316]";

const btnDanger =
  "data-button rounded-xl bg-red-600 px-4 py-2 text-sm font-semibold text-white hover:bg-red-700 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-red-500";

const btnSecondary =
  "data-button rounded-xl border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 dark:border-[#333] dark:text-gray-300 dark:hover:bg-[#1a1a1a]";

export default function RejeitarEncomendaPage() {
  const params = useParams();
  const router = useRouter();
  const id = params.id as string;
  const [mounted, setMounted] = useState(false);
  const [motivo, setMotivo] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const submittingRef = useRef(false);
  const [apiEncomenda, setApiEncomenda] = useState<{ estado?: string; clienteId?: string; cliente?: { nome?: string } } | null | undefined>(undefined);
  const [loadingApi, setLoadingApi] = useState(true);

  const idNum = parseInt(id, 10);
  const isApiId = !Number.isNaN(idNum);
  const encomenda = apiEncomenda ? { estado: apiEncomenda.estado, clienteId: apiEncomenda.clienteId ?? "", cliente: apiEncomenda.cliente } : null;

  useEffect(() => {
    setMounted(true);
  }, [id]);

  useEffect(() => {
    if (!mounted || !isApiId) {
      setApiEncomenda(null);
      setLoadingApi(false);
      return;
    }
    const token = getToken();
    if (!token) {
      setLoadingApi(false);
      return;
    }
    fetchRejeitar(token, idNum)
      .then((data) => setApiEncomenda(data as { estado?: string; clienteId?: string; cliente?: { nome?: string } }))
      .catch(() => setApiEncomenda(null))
      .finally(() => setLoadingApi(false));
  }, [mounted, id, idNum, isApiId]);

  if (!mounted) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-[#fafafa] dark:bg-[#0a0a0a]">
        <div className="h-8 w-8 animate-spin rounded-full border-2 border-[#f97316] border-t-transparent" />
      </div>
    );
  }

  if (loadingApi && isApiId && getToken()) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-[#fafafa] dark:bg-[#0a0a0a]">
        <div className="h-8 w-8 animate-spin rounded-full border-2 border-[#f97316] border-t-transparent" />
      </div>
    );
  }

  if (!encomenda) {
    return (
      <div className="min-h-screen bg-[#f8f7f5] dark:bg-[#0a0a0a]">
        <Navbar />
        <main style={{ paddingTop: CONTENT_OFFSET_TOP }} className="p-8">
          <p className="text-gray-600 dark:text-gray-400">Encomenda n├úo encontrada.</p>
          <Link href="/encomendas" className="mt-4 inline-block text-[#f97316] hover:underline">
            ÔåÉ Voltar ├ás Encomendas
          </Link>
        </main>
      </div>
    );
  }

  if (encomenda.estado !== "Pendente" && encomenda.estado !== "Aceite") {
    router.replace(`/encomendas/${id}?erro=1`);
    return null;
  }

  const handleConfirmar = async (e: React.FormEvent) => {
    e.preventDefault();
    if (submittingRef.current) return;
    const token = getToken();
    if (!isApiId || !token) return;
    submittingRef.current = true;
    setSubmitting(true);
    try {
      await postRejeitar(token, idNum, { motivoRejeicao: motivo.trim() || undefined });
      router.push(`/encomendas/${id}?rejeitada=1`);
    } catch {
      router.push(`/encomendas/${id}?erro=1`);
    } finally {
      submittingRef.current = false;
      setSubmitting(false);
    }
  };

  const clienteNome = encomenda.cliente?.nome ?? encomenda.clienteId;

  return (
    <div className="min-h-screen bg-[#f8f7f5] text-[#1c1917] dark:bg-[#0a0a0a] dark:text-white">
      <Navbar />

      <main
        className="relative px-6 pt-14 pb-10 sm:px-8"
        style={{ paddingTop: CONTENT_OFFSET_TOP }}
      >
        <div className="mx-auto max-w-2xl">
          <motion.div
            initial={fadeInUp.initial}
            animate={fadeInUp.animate}
            transition={transitionSmooth}
          >
            <h1 className="font-heading text-2xl tracking-tight sm:text-3xl">
              Rejeitar encomenda
            </h1>
            <p className="mt-1 text-[#57534e] dark:text-gray-400">
              Encomenda #{id} ┬À Cliente: {clienteNome} ┬À Estado atual: {encomenda.estado}
            </p>
          </motion.div>

          <motion.div
            initial={fadeInUp.initial}
            animate={fadeInUp.animate}
            transition={{ ...transitionSmooth, delay: 0.05 }}
            className="card-hover mt-10 rounded-2xl border border-[#e7e5e4] bg-white p-6 dark:border-[#1f1f1f] dark:bg-[#111] sm:p-8"
          >
            <p className="rounded-xl border border-amber-200 bg-amber-50 px-4 py-3 text-sm text-amber-800 dark:border-amber-800 dark:bg-amber-900/20 dark:text-amber-200">
              Ao confirmar, o stock reservado para esta encomenda ser├í libertado e a encomenda passar├í ao estado Rejeitada.
            </p>

            <form onSubmit={handleConfirmar} className="mt-6 space-y-6">
              <div>
                <label htmlFor="motivo" className={labelClass}>
                  Motivo de rejei├º├úo (opcional, m├íx. 500 caracteres)
                </label>
                <textarea
                  id="motivo"
                  value={motivo}
                  onChange={(e) => setMotivo(e.target.value.slice(0, 500))}
                  maxLength={500}
                  rows={4}
                  className={`${inputClass} mt-2 w-full`}
                  placeholder="Ex.: stock insuficiente, pedido cancelado pelo cliente..."
                />
              </div>
              <div className="flex flex-wrap gap-3">
                <button type="submit" className={btnDanger} disabled={submitting}>
                  {submitting ? "A processarÔÇª" : "Confirmar rejei├º├úo"}
                </button>
                <Link href={`/encomendas/${id}`} className={btnSecondary}>
                  Cancelar
                </Link>
              </div>
            </form>
          </motion.div>
        </div>
      </main>
    </div>
  );
}

