                            accept={FILE_ACCEPT}
                            className={`${inputClass} mt-1`}
                            onChange={(e) => {
                              setExtrasFiles((prev) => {
                                const next = [...prev];
                                while (next.length <= i) next.push(null);
                                next[i] = e.target.files?.[0] ?? null;
                                return next;
