              {!docs.cartaoCidadao && !docs.adr && !docs.licencaOperador && !docs.outros && docs.extras.length === 0 && (
                <p className="text-sm text-gray-500 dark:text-gray-400">Nenhum documento guardado.</p>
              )}
            </div>
          </motion.section>
        </div>
      </main>
    </div>
  );
}

