/** Resposta da API pode usar nome ou nomeCompleto; userIdsConfirmados vem no corpo da lista */
function mapApiToFuncionario(item: Record<string, unknown>, userIdsConfirmados?: string[]): Funcionario {
  const nome = (item.nomeCompleto ?? item.nome ?? "") as string;
  const userId = (item.userId ?? item.UserId) as string | undefined;
  const contaAssociada = !!userId;
  const confirmados = userIdsConfirmados ?? [];
  const emailConfirmado = contaAssociada ? confirmados.includes(userId!) : undefined;
  return {
    id: String(item.id ?? item.Id ?? ""),
    nomeCompleto: nome,
    nif: (item.nif ?? item.NIF) as string | undefined,
    email: (item.email ?? item.Email) as string | undefined,
    telefone: (item.telefone ?? item.Telefone) as string | undefined,
    morada: (item.morada ?? item.Morada) as string | undefined,
    cargo: (item.cargo ?? item.Cargo ?? "Comercial") as CargoFuncionario,
    dataRegisto: String(item.dataRegisto ?? item.DataRegisto ?? new Date().toISOString()),
    contaAssociada,
    emailConfirmado,
    userId,
  };
}

function FuncionariosContent() {
  const searchParams = useSearchParams();
  const router = useRouter();
  const pathname = usePathname();
  const { user } = useUser();
  const canGerirFuncionarios = (user?.permissions ?? []).includes("funcionarios.gerir");
  const eliminado = searchParams.get("eliminado") === "1";
  const columns = useMemo(() => funcionariosColumns(), []);

  const {
    data: funcionarios = [],
    isLoading: loading,
    isRefetching,
    error: queryError,
  } = useQuery({
    queryKey: ["funcionarios"],
    queryFn: async (): Promise<Funcionario[]> => {
      const token = getToken();
      if (!token) {
        if (pathname !== "/login") router.replace("/login");
        throw new Error("Sess├úo expirada. Fa├ºa login novamente.");
      }
      const res = await fetch(apiPath("api/funcionarios"), {
        headers: { Authorization: `Bearer ${token}` },
      });
      if (!res.ok) {
        if (res.status === 401) {
          router.replace("/login");
          throw new Error("Sess├úo expirada. Fa├ºa login novamente.");
        }
        throw new Error(
          res.status === 404
            ? "Recurso n├úo encontrado."
            : "Erro ao carregar funcion├írios."
        );
      }
      const data = (await safeParseJson(res)) as unknown;
      const dataObj = data as { items?: unknown[]; userIdsConfirmados?: string[] } | null;
      const arr = Array.isArray(dataObj?.items) ? dataObj.items : [];
      const userIdsConfirmados = Array.isArray(dataObj?.userIdsConfirmados) ? dataObj.userIdsConfirmados : [];
      return arr.map((item) =>
        mapApiToFuncionario(item as Record<string, unknown>, userIdsConfirmados)
      );
    },
    staleTime: 30 * 1000,
    retry: 3,
    enabled: !!getToken(),
  });

  const error =
    queryError instanceof Error
      ? queryError.message === "Failed to fetch"
        ? "Falha de rede. Verifique se a API est├í a correr (NEXT_PUBLIC_API_URL) e se CORS permite pedidos do frontend."
        : queryError.message
      : queryError
        ? "Erro ao carregar funcion├írios."
        : null;

  return (
    <div className="min-h-screen bg-[#f8f7f5] text-[#1c1917] dark:bg-[#0a0a0a] dark:text-white">
      <Navbar />

      <main
        className="relative px-6 pt-14 pb-10 sm:px-8"
        style={{ paddingTop: CONTENT_OFFSET_TOP }}
      >
        <div className="mx-auto max-w-6xl">
          <motion.div
            initial={fadeInUp.initial}
            animate={fadeInUp.animate}
            transition={transitionSmooth}
            className="flex flex-col gap-5 sm:flex-row sm:items-center sm:justify-between"
          >
            <div>
              <h1 className="font-heading text-2xl tracking-tight text-[#1c1917] dark:text-white sm:text-3xl">
                Funcion├írios
              </h1>
              <p className="mt-1 flex items-center gap-2 text-[#57534e] dark:text-gray-400">
                Listar, pesquisar e gerir fichas de funcion├írios.
                {isRefetching && !loading && (
                  <span className="inline-flex items-center gap-1.5 text-xs text-[#78716c] dark:text-gray-500">
                    <span className="h-1.5 w-1.5 shrink-0 animate-pulse rounded-full bg-[#f97316]" />
                    A atualizar
                  </span>
                )}
              </p>
            </div>
            <Link href="/funcionarios/novo" className={btnPrimary}>
              Adicionar funcion├írio
            </Link>
          </motion.div>

          {eliminado && (
            <motion.p
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={transitionSmooth}
              className="mt-5 rounded-xl bg-green-100 px-4 py-3 text-sm text-green-800 dark:bg-green-900/30 dark:text-green-400"
            >
              Funcion├írio eliminado com sucesso.
            </motion.p>
          )}

          {error && (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={transitionSmooth}
              className="mt-5 rounded-xl bg-red-100 px-4 py-3 text-sm text-red-800 dark:bg-red-900/30 dark:text-red-400"
            >
              {error}
            </motion.div>
          )}

          <motion.div
            initial={fadeInUp.initial}
            animate={fadeInUp.animate}
            transition={{ ...transitionSmooth, delay: 0.05 }}
            className="card-hover mt-10 rounded-2xl border border-[#e7e5e4] bg-white p-5 shadow-[0_1px_3px_rgba(0,0,0,0.06)] dark:border-[#1f1f1f] dark:bg-[#111] dark:shadow-none sm:p-6"
