            PIROFAFE
          </Link>
        </div>
      </header>

      <main className="mx-auto max-w-md px-4 py-14 sm:px-6">
        <motion.div
          initial={fadeInUp.initial}
          animate={fadeInUp.animate}
          transition={transitionSmooth}
          className="card-hover rounded-2xl border border-[#e7e5e4] bg-white p-8 shadow-[0_1px_3px_rgba(0,0,0,0.06)] dark:border-[#1f1f1f] dark:bg-[#111] dark:shadow-none sm:p-10"
        >
          <h1 className="font-heading text-2xl tracking-tight text-gray-900 dark:text-white sm:text-3xl">
            Criar primeiro utilizador
          </h1>
          <p className="mt-2 text-sm text-gray-600 dark:text-gray-400">
            Como n├úo existem contas no sistema, crie a primeira. Ser├í administrador.
          </p>

          <form onSubmit={handleSubmit} className="mt-8 space-y-5">
            <div>
              <label htmlFor="reg-nome" className={labelClass}>
                Nome (opcional)
              </label>
              <input
                id="reg-nome"
                type="text"
                value={nome}
                onChange={(e) => setNome(e.target.value)}
                className={inputClass}
                placeholder="O seu nome"
              />
            </div>
            <div>
              <label htmlFor="reg-email" className={labelClass}>
                Email *
              </label>
              <input
                id="reg-email"
                type="email"
                required
                autoComplete="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className={inputClass}
                placeholder="email@exemplo.pt"
              />
            </div>
            <div>
              <label htmlFor="reg-password" className={labelClass}>
                Palavra-passe *
              </label>
              <input
                id="reg-password"
                type="password"
                required
                minLength={6}
                autoComplete="new-password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className={inputClass}
                placeholder="M├¡nimo 6 caracteres"
              />
            </div>
            <div>
              <label htmlFor="reg-confirmar" className={labelClass}>
                Confirmar palavra-passe *
              </label>
              <input
                id="reg-confirmar"
                type="password"
                required
                autoComplete="new-password"
                value={confirmar}
                onChange={(e) => setConfirmar(e.target.value)}
                className={inputClass}
                placeholder="Repita a palavra-passe"
              />
            </div>

            {message && (
              <p className="text-sm text-red-600 dark:text-red-400">{message}</p>
            )}

            <button type="submit" className={btnPrimary} disabled={loading}>
              {loading ? "A criar contaÔÇª" : "Criar conta"}
            </button>
          </form>

          <p className="mt-6 text-center text-sm text-gray-500 dark:text-gray-400">
            <Link href="/login" className="text-[#f97316] hover:underline">
              ÔåÉ Voltar ao in├¡cio de sess├úo
            </Link>
          </p>
        </motion.div>
      </main>
    </div>
  );
}

