                        <td className="py-2 pr-4 text-right">{d.distanciaMinima_m}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </motion.section>
          )}

          {/* Licen├ºas do evento */}
          {servico.licencasEvento.length > 0 && (
            <motion.section
              initial={fadeInUp.initial}
              animate={fadeInUp.animate}
              transition={{ ...transitionSmooth, delay: 0.12 }}
              className="mt-6 rounded-2xl border border-[#e7e5e4] bg-white p-6 shadow-sm dark:border-[#1f1f1f] dark:bg-[#111]"
            >
              <h2 className="mb-1 text-lg font-semibold">Licen├ºas do evento</h2>
              <p className="mb-4 text-sm text-[#57534e] dark:text-gray-400">
                Duas fases: <strong className="font-medium text-[#1c1917] dark:text-white">papelada gerada</strong> no sistema e, depois, o{" "}
                <strong className="font-medium text-[#1c1917] dark:text-white">registo definitivo</strong> autorizado pelas entidades reguladoras. A barra de
                progresso conta s├│ as autoriza├º├Áes definitivas obrigat├│rias.
              </p>
              {canGerirServicos && (
                <div className="mb-4 rounded-xl border border-dashed border-[#fdba74]/60 bg-[#fffbeb] px-4 py-3 dark:border-[#78350f]/50 dark:bg-[#1c1410]/80">
                  <p className="text-sm font-medium text-[#9a3412] dark:text-[#fdba74]">Assistente de preenchimento</p>
                  <p className="mt-1 text-sm text-[#57534e] dark:text-gray-400">
                    Na coluna ┬½Papelada gerada┬╗, abra o registo e use o assistente para o texto das observa├º├Áes. Na coluna ┬½Autoriza├º├úo definitiva┬╗, registe o
                    documento oficial (n.┬║, validade, PDF).
                  </p>
                </div>
              )}
              {servico.licencasObrigatoriasTotal > 0 && (
                <p className="mb-2 text-sm text-[#57534e] dark:text-gray-400">
                  {servico.licencasObrigatoriasEntregues} de {servico.licencasObrigatoriasTotal} autoriza├º├Áes definitivas obrigat├│rias com ficheiro
                </p>
              )}
              <div className="mb-4 h-2 overflow-hidden rounded-full bg-gray-200 dark:bg-[#333]">
                <div
                  className="h-full rounded-full bg-green-500 transition-all"
                  style={{
                    width:
                      servico.licencasObrigatoriasTotal > 0
                        ? `${(100 * servico.licencasObrigatoriasEntregues) / servico.licencasObrigatoriasTotal}%`
                        : "0%",
                  }}
                />
              </div>
              <ul className="space-y-5">
                {servico.licencasEvento.map((linha) => {
                  const iconEstado = (e: number) => (e === 2 ? "Ô£à" : e === 1 ? "ÔÜá´©Å" : "ÔØî");
                  const hrefLic = (origem: 0 | 1, lic?: ServicoLicenca) => {
                    const p = new URLSearchParams({ tipo: linha.tipo });
                    p.set("origem", String(origem));
                    if (lic?.id) p.set("licencaId", lic.id);
                    return `/servicos/${servico.id}/licenca?${p}`;
                  };
                  const renderCelula = (
                    titulo: string,
                    origem: 0 | 1,
                    lic: ServicoLicenca | undefined,
                    estado: number,
                    badgeObrigatorio: boolean
                  ) => {
                    const validadeExpirada = lic?.dataValidade && new Date(lic.dataValidade) < new Date();
                    return (
                      <div className="min-w-0 flex-1 rounded-xl border border-[#e7e5e4] bg-[#fafaf9] p-3 dark:border-[#333] dark:bg-[#141414]">
                        <p className="text-xs font-semibold uppercase tracking-wide text-[#78716c] dark:text-gray-500">
                          {titulo}
                          {badgeObrigatorio && (
                            <span className="ml-1.5 rounded bg-gray-200 px-1.5 py-0.5 text-[0.65rem] font-normal normal-case dark:bg-[#333]">obrigat├│rio</span>
                          )}
                        </p>
                        <div className="mt-2 flex flex-wrap items-center gap-2">
                          <span className="text-lg leading-none">{iconEstado(estado)}</span>
                          {lic?.numeroDocumento && (
                            <span className="text-sm text-[#57534e] dark:text-gray-400">{lic.numeroDocumento}</span>
                          )}
                          {lic?.dataValidade && (
                            <span
                              className={
                                validadeExpirada ? "text-sm text-red-600 dark:text-red-400" : "text-sm text-[#57534e] dark:text-gray-400"
                              }
                            >
                              Val. {new Date(lic.dataValidade).toLocaleDateString("pt-PT")}
                            </span>
                          )}
                          {canGerirServicos && (
                            <Link href={hrefLic(origem, lic)} className="rounded-lg border border-gray-300 px-2 py-1 text-xs dark:border-[#333]">
                              {lic ? "Editar" : "Adicionar"}
                            </Link>
                          )}
                        </div>
                      </div>
                    );
                  };

                  if (linha.tipo === "OUTRO") {
                    const ped = linha.licencaPedido;
                    const def = linha.licencaDefinitiva;
                    const key = `outro-${ped?.id ?? ""}-${def?.id ?? ""}-${linha.nomeExibicao}`;
                    return (
                      <li key={key} className="border-b border-[#f5f5f4] pb-4 last:border-0 dark:border-[#1a1a1a]">
                        <div className="flex flex-wrap items-center gap-2">
                          <span className="text-lg leading-none">{iconEstado(Math.max(linha.estadoPedido, linha.estadoDefinitiva))}</span>
                          <span className="font-medium">{linha.nomeExibicao}</span>
                        </div>
                        <div className="mt-2 grid gap-3 sm:grid-cols-2">
                          {renderCelula("Papelada gerada", 0, ped, linha.estadoPedido, false)}
                          {renderCelula("Autoriza├º├úo definitiva", 1, def, linha.estadoDefinitiva, false)}
                        </div>
                      </li>
                    );
                  }

                  return (
                    <li key={linha.tipo} className="border-b border-[#f5f5f4] pb-4 last:border-0 dark:border-[#1a1a1a]">
                      <p className="font-medium text-[#1c1917] dark:text-white">{linha.nomeExibicao}</p>
                      <div className="mt-2 grid gap-3 sm:grid-cols-2">
                        {renderCelula("1. Papelada gerada (pedido)", 0, linha.licencaPedido, linha.estadoPedido, false)}
                        {renderCelula("2. Autoriza├º├úo definitiva", 1, linha.licencaDefinitiva, linha.estadoDefinitiva, linha.obrigatorio)}
                      </div>
                    </li>
                  );
                })}
              </ul>
            </motion.section>
          )}

          {/* Documenta├º├úo do evento */}
          {servico.documentosExtras.length > 0 && (
            <motion.section
              initial={fadeInUp.initial}
              animate={fadeInUp.animate}
              transition={{ ...transitionSmooth, delay: 0.16 }}
              className="mt-6 rounded-2xl border border-[#e7e5e4] bg-white p-6 shadow-sm dark:border-[#1f1f1f] dark:bg-[#111]"
            >
              <h2 className="mb-4 text-lg font-semibold">Documenta├º├úo do evento</h2>
              <ul className="flex flex-wrap gap-2">
                {servico.documentosExtras.map((doc) => (
                  <li key={doc.id}>
                    <span className="rounded-lg border border-gray-300 px-3 py-1.5 text-sm dark:border-[#333]">
                      {doc.nome || "Documento"}
                    </span>
                  </li>
                ))}
              </ul>
            </motion.section>
          )}
        </div>
      </main>
    </div>
  );
}

"use client";

import { useState, useEffect, Suspense } from "react";
import Link from "next/link";
import { useSearchParams, useRouter } from "next/navigation";
import { useQuery } from "@tanstack/react-query";
import { motion } from "framer-motion";
import Navbar, { CONTENT_OFFSET_TOP } from "@/app/components/Navbar";
import { getToken } from "@/app/lib/auth";
import { useUser } from "@/app/context/UserContext";
import { fetchServicosFromApi } from "@/app/lib/servicos";
import { fadeInUp, transitionSmooth } from "@/app/lib/animations";

type ListItem = {
  id: string;
  clienteId: string;
  dataServico: string;
  local?: string;
  publicoPrivado?: string;
  cliente?: { id: string; nome: string } | null;
  encomenda?: { id: string; estado?: string } | null;
  responsavelTecnico?: { id: string; nomeCompleto: string } | null;
};

type ServicosApiData = {
  lista: ListItem[];
  total: number;
  clientes: Array<{ id: string; nome: string }>;
};

const btnPrimary =
  "data-button rounded-xl bg-[#f97316] px-4 py-2 text-sm font-semibold text-black transition-[opacity,background-color] duration-200 hover:opacity-90 focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[#f97316]";

const ITENS_POR_PAGINA = 20;
const MAX_PAGINAS_VISIVEIS = 10;

function ServicosContent() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const { user } = useUser();
  const permissions = user?.permissions ?? [];
  const canGerirServicos = permissions.includes("servicos.gerir");

  const clienteId = searchParams.get("clienteId") ?? undefined;
  const dataDesde = searchParams.get("dataDesde") ?? "";
  const dataAte = searchParams.get("dataAte") ?? "";
  const pagina = Math.max(1, parseInt(searchParams.get("pagina") ?? "1", 10) || 1);

  const filters =
    clienteId || dataDesde || dataAte
      ? { clienteId, dataDesde: dataDesde || undefined, dataAte: dataAte || undefined }
      : undefined;

  const {
    data: apiData,
    isLoading: loadingApi,
    isRefetching,
    error: queryError,
  } = useQuery({
    queryKey: ["servicos", clienteId, dataDesde, dataAte, pagina],
    queryFn: async (): Promise<ServicosApiData> => {
      const token = getToken();
      if (!token) throw new Error("Sess├úo expirada. Fa├ºa login novamente.");
      const res = await fetchServicosFromApi(token, filters, pagina, ITENS_POR_PAGINA);
      return {
        lista: res.lista as ListItem[],
        total: res.total,
        clientes: (res.clientes ?? []).map((c: { id?: number; nome?: string }) => ({
          id: String(c.id ?? ""),
          nome: String(c.nome ?? ""),
        })),
      };
    },
    staleTime: 30 * 1000,
    retry: 3,
    enabled: !!getToken(),
  });

  const lista = apiData?.lista ?? [];
  const total = apiData?.total ?? 0;
  const clientes = apiData?.clientes ?? [];
  const totalPaginas = Math.max(1, Math.ceil(total / ITENS_POR_PAGINA));
  const start = total === 0 ? 0 : (pagina - 1) * ITENS_POR_PAGINA + 1;
  const end = Math.min(pagina * ITENS_POR_PAGINA, total);

  const setFiltros = (updates: { clienteId?: string; dataDesde?: string; dataAte?: string; pagina?: number }) => {
    const p = new URLSearchParams(searchParams.toString());
    if (updates.clienteId !== undefined) (updates.clienteId ? p.set("clienteId", updates.clienteId) : p.delete("clienteId"));
    if (updates.dataDesde !== undefined) (updates.dataDesde ? p.set("dataDesde", updates.dataDesde) : p.delete("dataDesde"));
    if (updates.dataAte !== undefined) (updates.dataAte ? p.set("dataAte", updates.dataAte) : p.delete("dataAte"));
    if (updates.pagina !== undefined) p.set("pagina", String(updates.pagina));
    router.push(`/servicos?${p.toString()}`);
  };

  return (
    <div className="min-h-screen bg-[#f8f7f5] text-[#1c1917] dark:bg-[#0a0a0a] dark:text-white">
      <Navbar />

      <main className="relative px-6 pt-14 pb-10 sm:px-8" style={{ paddingTop: CONTENT_OFFSET_TOP }}>
        <div className="mx-auto max-w-6xl">
          <motion.div
            initial={fadeInUp.initial}
            animate={fadeInUp.animate}
            transition={transitionSmooth}
            className="flex flex-col gap-5 sm:flex-row sm:flex-wrap sm:items-center sm:justify-between"
          >
            <div>
              <h1 className="font-heading text-2xl tracking-tight text-[#1c1917] dark:text-white sm:text-3xl">
                Servi├ºos
              </h1>
              <p className="mt-1 flex items-center gap-2 text-sm text-[#57534e] dark:text-gray-400">
                Opera├º├Áes no terreno. Cada servi├ºo est├í ligado a uma encomenda conclu├¡da.
                {isRefetching && !loadingApi && (
                  <span className="inline-flex items-center gap-1.5 text-xs text-[#78716c] dark:text-gray-500">
                    <span className="h-1.5 w-1.5 shrink-0 animate-pulse rounded-full bg-[#f97316]" />
                    A atualizar
                  </span>
                )}
              </p>
            </div>
            {canGerirServicos && (
              <Link href="/servicos/novo" className={btnPrimary}>
                Novo servi├ºo
              </Link>
            )}
          </motion.div>

          {queryError && (
            <motion.p
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={transitionSmooth}
              className="mt-5 rounded-xl bg-red-100 px-4 py-3 text-sm text-red-800 dark:bg-red-900/30 dark:text-red-400"
            >
              {queryError instanceof Error
                ? queryError.message === "Failed to fetch"
                  ? "Falha de rede. Verifique se a API est├í a correr (NEXT_PUBLIC_API_URL) e se CORS permite pedidos do frontend."
                  : queryError.message
                : "Erro ao carregar servi├ºos."}
            </motion.p>
          )}

          <motion.div
            initial={fadeInUp.initial}
            animate={fadeInUp.animate}
            transition={{ ...transitionSmooth, delay: 0.05 }}
            className="card-hover mt-10 rounded-2xl border border-[#e7e5e4] bg-white p-5 shadow-[0_1px_3px_rgba(0,0,0,0.06)] dark:border-[#1f1f1f] dark:bg-[#111] sm:p-6"
          >
            {/* Filtros GET: Cliente, Data desde, Data at├®, Filtrar (pagina=1) */}
            <form
              className="flex flex-wrap items-end gap-4"
              onSubmit={(e) => {
                e.preventDefault();
                setFiltros({ pagina: 1 });
              }}
            >
              <div>
                <label htmlFor="servicos-cliente" className="block text-sm font-medium text-gray-700 dark:text-gray-300">
                  Cliente
                </label>
                <select
                  id="servicos-cliente"
                  value={clienteId ?? ""}
                  onChange={(e) => setFiltros({ clienteId: e.target.value || undefined, pagina: 1 })}
                  className="mt-1 rounded-xl border border-gray-300 bg-white px-3 py-2 text-sm text-gray-900 dark:border-[#333] dark:bg-[#1a1a1a] dark:text-white"
                >
                  <option value="">ÔÇö Todos ÔÇö</option>
                  {clientes.map((c) => (
                    <option key={c.id} value={c.id}>
                      {c.nome}
                    </option>
                  ))}
                </select>
              </div>
              <div>
                <label htmlFor="servicos-desde" className="block text-sm font-medium text-gray-700 dark:text-gray-300">
                  Data desde
                </label>
                <input
                  id="servicos-desde"
                  type="date"
                  value={dataDesde}
                  onChange={(e) => setFiltros({ dataDesde: e.target.value || undefined, pagina: 1 })}
                  className="mt-1 rounded-xl border border-gray-300 bg-white px-3 py-2 text-sm dark:border-[#333] dark:bg-[#1a1a1a] dark:text-white"
                />
              </div>
              <div>
                <label htmlFor="servicos-ate" className="block text-sm font-medium text-gray-700 dark:text-gray-300">
                  Data at├®
                </label>
                <input
                  id="servicos-ate"
                  type="date"
                  value={dataAte}
                  onChange={(e) => setFiltros({ dataAte: e.target.value || undefined, pagina: 1 })}
                  className="mt-1 rounded-xl border border-gray-300 bg-white px-3 py-2 text-sm dark:border-[#333] dark:bg-[#1a1a1a] dark:text-white"
                />
              </div>
              <button type="submit" className={btnPrimary}>
                Filtrar
              </button>
            </form>

            <p className="mt-4 flex items-center gap-2 text-sm text-[#57534e] dark:text-gray-400">
              {loadingApi ? "A carregarÔÇª " : ""}
              A mostrar {start}ÔÇô{end} de {total}
            </p>

            <div className="mt-6 overflow-x-auto">
              {loadingApi ? (
                <div className="flex flex-col items-center justify-center gap-3 py-12 text-[#57534e] dark:text-gray-400">
                  <div className="h-8 w-8 animate-spin rounded-full border-2 border-[#f97316] border-t-transparent" />
                  <span>A carregar servi├ºosÔÇª</span>
                </div>
              ) : lista.length === 0 ? (
                <div className="rounded-xl border border-dashed border-[#e7e5e4] bg-[#fafaf9] py-12 text-center dark:border-[#333] dark:bg-[#0a0a0a]">
                  <p className="text-[#57534e] dark:text-gray-400">Nenhum servi├ºo encontrado.</p>
                  {canGerirServicos && (
                    <Link href="/servicos/novo" className={btnPrimary + " mt-4 inline-block"}>
                      Novo servi├ºo
                    </Link>
                  )}
                </div>
              ) : (
                <>
                  <div className="space-y-3 lg:hidden">
                    {lista.map((s) => (
                      <Link
                        key={s.id}
                        href={`/servicos/${s.id}`}
                        className="block rounded-xl border border-[#e7e5e4] bg-white p-4 dark:border-[#1f1f1f] dark:bg-[#111]"
                      >
                        <p className="font-medium text-[#1c1917] dark:text-white">#{s.id}</p>
                        <p className="mt-0.5 text-sm text-[#57534e] dark:text-gray-400">{s.cliente?.nome ?? s.clienteId}</p>
